static Item js_runtime_make_string_item(const char* str, int len) {
    return (Item){.item = s2it(heap_strcpy((char*)str, len))};
}

static const JubeTypeDef* js_host_object_type(Item object) {
    if (get_type_id(object) != LMD_TYPE_VMAP || !object.vmap || !object.vmap->host_type) {
        return NULL;
    }
    return jube_find_type_by_host_type(object.vmap->host_type);
}

static bool js_host_object_get_property(Item object, Item key, Item* out) {
    // DOM3: declared-interface types dispatch through compiled member records
    if (jube_member_get(object, key, out)) return true;
    const JubeTypeDef* type = js_host_object_type(object);
    return type && type->host_ops && type->host_ops->get_property &&
        type->host_ops->get_property(object, key, out);
}

static bool js_host_object_set_property(Item object, Item key, Item value, Item* out) {
    if (jube_member_set(object, key, value, out)) return true;
    const JubeTypeDef* type = js_host_object_type(object);
    return type && type->host_ops && type->host_ops->set_property &&
        type->host_ops->set_property(object, key, value, out);
}

static inline void js_note_event_handler_property_set(Item object,
                                                       const char* name,
                                                       int name_len,
                                                       Item value) {
    if (!name || name_len < 3 || name[0] != 'o' || name[1] != 'n') return;
    js_dom_event_handler_property_set(object, name, name_len, value);
}

static inline void js_note_event_handler_property_set(Item object, Item key,
                                                       Item value) {
    if (get_type_id(key) != LMD_TYPE_STRING) return;
    String* name = it2s(key);
    if (!name || name->len > 63) return;
    js_note_event_handler_property_set(object, name->chars, (int)name->len, value);
}

static bool js_host_object_call_method(Item object,
                                       Item method_name,
                                       Item* args,
                                       int argc,
                                       Item* out) {
    if (jube_member_call(object, method_name, args, argc, out)) return true;
    const JubeTypeDef* type = js_host_object_type(object);
    return type && type->host_ops && type->host_ops->call_method &&
        type->host_ops->call_method(object, method_name, args, argc, out);
}

static bool js_host_object_prototype(Item object, Item* out) {
    if (jube_member_prototype(object, out)) return true;
    const JubeTypeDef* type = js_host_object_type(object);
    if (!type || !type->host_ops || !type->host_ops->prototype || !out) return false;
    *out = type->host_ops->prototype(object);
    return true;
}

extern "C" Item js_using_dispose(Item resource) {
    if (resource.item == 0 || resource.item == ITEM_NULL ||
            get_type_id(resource) == LMD_TYPE_UNDEFINED) {
        return (Item){.item = ITEM_JS_UNDEFINED};
    }
    Item name = js_runtime_make_string_item("dispose", 7);
    Item dispose_key = js_symbol_well_known(name);
    Item dispose = js_property_get(resource, dispose_key);
    if (get_type_id(dispose) != LMD_TYPE_FUNC) {
        return js_throw_type_error("Object is not disposable");
    }
    return js_call_function(dispose, resource, NULL, 0);
}

