struct JsGlobalVarModuleBinding {
    Item key;
    int index;
};

#define JS_GLOBAL_VAR_MODULE_BINDING_CAP 512

static JsGlobalVarModuleBinding js_global_var_module_bindings[JS_GLOBAL_VAR_MODULE_BINDING_CAP];
static int js_global_var_module_binding_count = 0;
static uint64_t js_global_var_module_binding_epoch = 0;
static Item js_global_var_module_binding_global = {0};

extern "C" Item js_get_global_this(void);
extern "C" Item js_vm_swap_global_this(Item next_global);
extern "C" uint64_t js_get_heap_epoch(void);
static Item js_262_eval_script(Item code);

static bool js_global_var_binding_key_same(Item a, Item b) {
    if (a.item == b.item) return true;
    if (get_type_id(a) != LMD_TYPE_STRING || get_type_id(b) != LMD_TYPE_STRING) return false;
    String* as = it2s(a);
    String* bs = it2s(b);
    return as && bs && as->len == bs->len &&
        memcmp(as->chars, bs->chars, (size_t)as->len) == 0;
}

static void js_global_var_binding_refresh(void) {
    Item global = js_get_global_this();
    uint64_t epoch = js_get_heap_epoch();
    if (js_global_var_module_binding_epoch == epoch &&
        js_global_var_module_binding_global.item == global.item) {
        return;
    }
    js_global_var_module_binding_epoch = epoch;
    js_global_var_module_binding_global = global;
    js_global_var_module_binding_count = 0;
}

extern "C" void js_register_global_var_module_binding(Item key, int64_t index) {
    js_global_var_binding_refresh();
    if (get_type_id(key) != LMD_TYPE_STRING || index < 0) return;
    for (int i = 0; i < js_global_var_module_binding_count; i++) {
        if (js_global_var_binding_key_same(js_global_var_module_bindings[i].key, key)) {
            js_global_var_module_bindings[i].index = (int)index;
            return;
        }
    }
    if (js_global_var_module_binding_count >= JS_GLOBAL_VAR_MODULE_BINDING_CAP) return;
    js_global_var_module_bindings[js_global_var_module_binding_count].key = key;
    js_global_var_module_bindings[js_global_var_module_binding_count].index = (int)index;
    js_global_var_module_binding_count++;
}

extern "C" void js_register_global_var_module_bindings_bulk(const Item* keys,
        const int* indices, int count) {
    js_global_var_binding_refresh();
    if (!keys || !indices || count <= 0) return;
    for (int i = 0; i < count; i++) {
        Item key = keys[i];
        int index = indices[i];
        if (get_type_id(key) != LMD_TYPE_STRING || index < 0) continue;
        bool updated = false;
        for (int j = 0; j < js_global_var_module_binding_count; j++) {
            if (js_global_var_binding_key_same(js_global_var_module_bindings[j].key, key)) {
                js_global_var_module_bindings[j].index = index;
                updated = true;
                break;
            }
        }
        if (updated) continue;
        if (js_global_var_module_binding_count >= JS_GLOBAL_VAR_MODULE_BINDING_CAP) return;
        js_global_var_module_bindings[js_global_var_module_binding_count].key = key;
        js_global_var_module_bindings[js_global_var_module_binding_count].index = index;
        js_global_var_module_binding_count++;
    }
}

static void js_sync_global_var_module_binding(Item object, Item key, Item value) {
    js_global_var_binding_refresh();
    if (object.item != js_global_var_module_binding_global.item ||
        get_type_id(key) != LMD_TYPE_STRING) {
        return;
    }
    for (int i = 0; i < js_global_var_module_binding_count; i++) {
        if (js_global_var_binding_key_same(js_global_var_module_bindings[i].key, key)) {
            // Global `var` bindings are backed by the global object. When code
            // writes through `this.x`/`globalThis.x`, keep the optimized module
            // slot coherent without making every identifier read a property get.
            js_set_module_var(js_global_var_module_bindings[i].index, value);
            return;
        }
    }
}

static bool js_reflect_target_is_object(Item target) {
    TypeId type = get_type_id(target);
    return type == LMD_TYPE_MAP || type == LMD_TYPE_ARRAY ||
           type == LMD_TYPE_FUNC || type == LMD_TYPE_ELEMENT;
}

static Item js_function_home_class(Item func_item) {
    if (get_type_id(func_item) != LMD_TYPE_FUNC) return ItemNull;
    JsFunction* fn = (JsFunction*)func_item.function;
    if (!fn || fn->properties_map.item == 0 || get_type_id(fn->properties_map) != LMD_TYPE_MAP) return ItemNull;
    bool found = false;
    Item home = js_map_get_fast_ext(fn->properties_map.map, JS_HOME_CLASS_KEY, JS_HOME_CLASS_KEY_LEN, &found);
    return found ? home : ItemNull;
}

static int js_private_key_class_index(String* private_key) {
    if (!private_key || private_key->len <= 10 ||
        strncmp(private_key->chars, "__private_", 10) != 0) return -1;
    const char* p = private_key->chars + 10;
    const char* end = private_key->chars + private_key->len;
    if (p >= end || *p < '0' || *p > '9') return -1;
    int idx = 0;
    while (p < end && *p >= '0' && *p <= '9') {
        idx = idx * 10 + (*p - '0');
        p++;
    }
    if (p >= end || *p != '_') return -1;
    return idx;
}

static int js_class_private_index(Item class_item) {
    if (get_type_id(class_item) != LMD_TYPE_MAP) return -1;
    bool found = false;
    Item index_item = js_map_get_fast_ext(class_item.map, JS_PRIVATE_CLASS_INDEX_KEY,
        JS_PRIVATE_CLASS_INDEX_KEY_LEN, &found);
    if (!found || get_type_id(index_item) != LMD_TYPE_INT) return -1;
    return (int)it2i(index_item);
}

extern "C" void js_set_private_class_index(Item class_item, int index) {
    if (get_type_id(class_item) != LMD_TYPE_MAP || index < 0) return;
    Item key = (Item){.item = s2it(heap_create_name(JS_PRIVATE_CLASS_INDEX_KEY, JS_PRIVATE_CLASS_INDEX_KEY_LEN))};
    Item val = (Item){.item = i2it(index)};
    js_property_set(class_item, key, val);
}

extern "C" Item js_bound_function_target(Item func_item) {
    if (get_type_id(func_item) != LMD_TYPE_FUNC) return ItemNull;
    JsFunction* fn = (JsFunction*)func_item.function;
    if (!fn || !(fn->flags & JS_FUNC_FLAG_HAS_BOUND_THIS)) return ItemNull;
    if (fn->properties_map.item == 0 || get_type_id(fn->properties_map) != LMD_TYPE_MAP) return ItemNull;
    bool found = false;
    Item target = js_map_get_fast_ext(fn->properties_map.map, JS_BOUND_TARGET_KEY, JS_BOUND_TARGET_KEY_LEN, &found);
    if (!found) return ItemNull;
    return target;
}

static Item js_bound_function_ultimate_target(Item func_item) {
    Item current = func_item;
    for (int depth = 0; depth < 32; depth++) {
        Item target = js_bound_function_target(current);
        if (target.item == ItemNull.item) return current;
        current = target;
    }
    return current;
}

static bool js_is_intrinsic_constructor_named(Item constructor, const char* name, int len) {
    if (get_type_id(constructor) != LMD_TYPE_FUNC || !name || len <= 0) return false;
    Item target = js_bound_function_ultimate_target(constructor);
    Item name_item = (Item){.item = s2it(heap_create_name(name, len))};
    Item intrinsic = js_get_constructor(name_item);
    return target.item == intrinsic.item;
}

static Item js_bound_function_effective_new_target(Item callee, Item new_target) {
    Item current = callee;
    Item effective = new_target;
    for (int depth = 0; depth < 32 && get_type_id(current) == LMD_TYPE_FUNC; depth++) {
        Item target = js_bound_function_target(current);
        if (target.item == ItemNull.item) break;
        if (effective.item == current.item) effective = target;
        current = target;
    }
    return effective;
}

extern "C" void js_set_method_home_from_target(Item target, Item fn_item) {
    if (get_type_id(fn_item) != LMD_TYPE_FUNC || get_type_id(target) != LMD_TYPE_MAP) return;
    Item home = ItemNull;
    bool class_proto_found = false;
    Item class_proto = js_map_get_fast(target.map, "__instance_proto__", 18, &class_proto_found);
    if (class_proto_found && class_proto.item != ItemNull.item) {
        home = target;
    } else {
        bool ctor_found = false;
        Item ctor = js_map_get_fast(target.map, "constructor", 11, &ctor_found);
        if (ctor_found && get_type_id(ctor) == LMD_TYPE_MAP) {
            bool ctor_proto_found = false;
            Item ctor_proto = js_map_get_fast(ctor.map, "__instance_proto__", 18, &ctor_proto_found);
            if (ctor_proto_found && ctor_proto.item != ItemNull.item) home = ctor;
        }
    }
    if (home.item == ItemNull.item || home.item == 0) return;
    Item home_key = (Item){.item = s2it(heap_create_name(JS_HOME_CLASS_KEY, JS_HOME_CLASS_KEY_LEN))};
    js_property_set(fn_item, home_key, home);
}

static bool js_is_function_prototype_map(Item item) {
    if (get_type_id(item) != LMD_TYPE_MAP) return false;
    bool is_proto = false;
    js_map_get_fast_ext(item.map, "__is_proto__", 12, &is_proto);
    return is_proto && js_class_id(item) == JS_CLASS_FUNCTION;
}

// v30: Helper to compute callback this value per ES spec OrdinaryCallBindThis.
// thisArg_item is the explicit thisArg (or ITEM_JS_UNDEFINED if not provided).
// For non-strict, non-arrow callbacks: undefined/null → globalThis.
static Item js_compute_callback_this(JsFunction* fn, Item thisArg_item) {
    if (!(fn->flags & JS_FUNC_FLAG_STRICT) && !(fn->flags & JS_FUNC_FLAG_ARROW)) {
        if (thisArg_item.item == ITEM_JS_UNDEFINED || thisArg_item.item == ITEM_NULL || thisArg_item.item == 0) {
            extern Item js_get_global_this();
            return js_get_global_this();
        }
        TypeId this_type = get_type_id(thisArg_item);
        if (this_type != LMD_TYPE_MAP && this_type != LMD_TYPE_ARRAY &&
            this_type != LMD_TYPE_ELEMENT && this_type != LMD_TYPE_FUNC &&
            this_type != LMD_TYPE_OBJECT && this_type != LMD_TYPE_VMAP) {
            return js_to_object(thisArg_item);
        }
    }
    return thisArg_item;
}

// Forward declarations for collection types (defined here, used in js_property_get and js_dispatch_builtin)
#define JS_COLLECTION_MAP 0
#define JS_COLLECTION_SET 1

struct JsCollectionOrderNode {
    Item key;
    Item value;
    JsCollectionOrderNode* next;
    JsCollectionOrderNode* prev;
    bool deleted;
};

struct JsCollectionData {
    HashMap* hmap;
    int type; // JS_COLLECTION_MAP or JS_COLLECTION_SET
    bool is_weak; // true for WeakMap/WeakSet
    JsCollectionOrderNode* order_head;
    JsCollectionOrderNode* order_tail;
};

static JsCollectionData* js_get_collection_data(Item obj);



// P2: Pre-computed size class for sizeof(Map) = 32 bytes → SIZE_CLASSES[1] = 32.
// Skips the class-index lookup in gc_heap_alloc and uses the bump-pointer fast path.
#define JS_MAP_SIZE_CLASS 1

// Create a new JS object as a Lambda Map (empty, using map_put for dynamic keys)
extern "C" Item js_new_object() {
    JS_EXEC_PROFILE_SCOPE(JS_EXEC_PROF_NEW_OBJECT);
    Map* m = (Map*)heap_calloc_class(sizeof(Map), LMD_TYPE_MAP, JS_MAP_SIZE_CLASS);
    m->type_id = LMD_TYPE_MAP;
    m->type = &EmptyMap;
    return (Item){.map = m};
}

// =============================================================================
// ES6 Proxy
// =============================================================================

// Helper macros: JsProxyData stores target/handler as uint64_t for C header compat
#define PD_TARGET(pd) ((Item){.item = (pd)->target})
#define PD_HANDLER(pd) ((Item){.item = (pd)->handler})
#define PD_PRIVATE_SLOTS(pd) ((Item){.item = (pd)->private_slots})

extern "C" bool js_is_proxy(Item obj) {
    return get_type_id(obj) == LMD_TYPE_MAP && obj.map->map_kind == MAP_KIND_PROXY;
}

extern "C" JsProxyData* js_get_proxy_data(Item obj) {
    if (!js_is_proxy(obj)) return NULL;
    return (JsProxyData*)obj.map->data;
}

extern "C" Item js_proxy_get_target(Item obj) {
    int depth = 0;
    while (js_is_proxy(obj) && depth < 32) {
        JsProxyData* pd = js_get_proxy_data(obj);
        if (!pd || pd->revoked) return ItemNull;
        obj = PD_TARGET(pd);
        depth++;
    }
    return obj;
}

static Item js_proxy_private_slots(Item proxy, bool create) {
    JsProxyData* pd = js_get_proxy_data(proxy);
    if (!pd || pd->revoked) return ItemNull;
    Item slots = PD_PRIVATE_SLOTS(pd);
    if (get_type_id(slots) == LMD_TYPE_MAP) return slots;
    if (!create) return ItemNull;
    slots = js_new_object();
    pd->private_slots = slots.item;
    return slots;
}

extern "C" bool js_proxy_has_callable_target(Item obj) {
    int depth = 0;
    while (js_is_proxy(obj) && depth < 32) {
        JsProxyData* pd = js_get_proxy_data(obj);
        if (!pd) return false;
        obj = PD_TARGET(pd);
        depth++;
    }
    TypeId type = get_type_id(obj);
    if (type == LMD_TYPE_FUNC) return true;
    if (type == LMD_TYPE_MAP) {
        bool own_ip = false;
        js_map_get_fast_ext(obj.map, "__instance_proto__", 18, &own_ip);
        if (own_ip) return true;
        if (js_class_id(obj) == JS_CLASS_FUNCTION) {
            bool own_proto = false;
            js_map_get_fast_ext(obj.map, "__is_proto__", 12, &own_proto);
            if (own_proto) return true;
        }
    }
    return false;
}

// helper: check if object is extensible (returns C bool)
static bool js_is_extensible(Item obj) {
    return it2b(js_to_boolean(js_object_is_extensible(obj)));
}

// helper: look up a trap function on the handler, returns ItemNull if not found
static Item js_proxy_get_trap(JsProxyData* pd, const char* trap_name, int trap_len) {
    if (pd->revoked) {
        js_throw_value(js_new_error_with_name(
            (Item){.item = s2it(heap_create_name("TypeError", 9))},
            (Item){.item = s2it(heap_create_name("Cannot perform operation on a revoked proxy", 44))}));
        return ItemNull;
    }
    Item handler_item = PD_HANDLER(pd);
    if (get_type_id(handler_item) != LMD_TYPE_MAP) return ItemNull;
    // ES §7.3.10 GetMethod: do a proper [[Get]] (must invoke accessors) and
    // then validate callability. js_map_get_fast skips accessor getters.
    Item trap = js_property_get_str(handler_item, trap_name, trap_len);
    if (js_exception_pending) return ItemNull;
    if (trap.item == ItemNull.item) return ItemNull;
    TypeId tt = get_type_id(trap);
    if (tt == LMD_TYPE_UNDEFINED || tt == LMD_TYPE_NULL) return ItemNull;
    if (tt != LMD_TYPE_FUNC) {
        char msg[96];
        snprintf(msg, sizeof(msg), "'%.*s' returned for property '%.*s' of object '#<Object>' is not a function",
                 trap_len, trap_name, trap_len, trap_name);
        js_throw_type_error(msg);
        return ItemNull;
    }
    return trap;
}

extern "C" Item js_proxy_new(Item target, Item handler) {
    // ES2020 §26.2.1.1: both target and handler must be objects
    TypeId tt = get_type_id(target);
    if (tt != LMD_TYPE_MAP && tt != LMD_TYPE_ARRAY && tt != LMD_TYPE_FUNC && tt != LMD_TYPE_ELEMENT) {
        return js_throw_type_error("Cannot create proxy with a non-object as target");
    }
    TypeId ht = get_type_id(handler);
    if (ht != LMD_TYPE_MAP && ht != LMD_TYPE_ARRAY && ht != LMD_TYPE_FUNC && ht != LMD_TYPE_ELEMENT) {
        return js_throw_type_error("Cannot create proxy with a non-object as handler");
    }

    JsProxyData* pd = (JsProxyData*)mem_alloc(sizeof(JsProxyData), MEM_CAT_JS_RUNTIME);
    pd->target = target.item;
    pd->handler = handler.item;
    pd->private_slots = ItemNull.item;
    pd->revoked = false;

    Map* m = (Map*)heap_calloc(sizeof(Map), LMD_TYPE_MAP);
    m->type_id = LMD_TYPE_MAP;
    m->map_kind = MAP_KIND_PROXY;
    m->type = &EmptyMap;
    m->data = pd;
    m->data_cap = 0;

    return (Item){.map = m};
}

// Proxy.revocable(target, handler) → { proxy, revoke }
extern "C" Item js_proxy_revocable(Item target, Item handler) {
    Item proxy = js_proxy_new(target, handler);
    if (js_exception_pending) return ItemNull;

    JsProxyData* pd = js_get_proxy_data(proxy);

    // create a fresh revoke function — each call to Proxy.revocable needs its own
    JsFunction* fn = (JsFunction*)pool_calloc(js_input->pool, sizeof(JsFunction));
    fn->type_id = LMD_TYPE_FUNC;
    fn->func_ptr = NULL;
    fn->param_count = 0;
    fn->formal_length = 0;
    fn->builtin_id = -3;  // sentinel: proxy revoke function
    fn->name = heap_create_name("", 0);
    fn->prototype = ItemNull;
    // store proxy data pointer in env[0]
    fn->env = (Item*)pool_calloc(js_input->pool, sizeof(Item));
    fn->env[0] = (Item){.item = (uint64_t)(uintptr_t)pd};
    fn->env_size = 1;

    Item revoke_fn = {.function = (Function*)fn};

    // build result object { proxy, revoke }
    Item result = js_new_object();
    js_property_set(result, (Item){.item = s2it(heap_create_name("proxy", 5))}, proxy);
    js_property_set(result, (Item){.item = s2it(heap_create_name("revoke", 6))}, revoke_fn);
    return result;
}

// Proxy [[Get]](key, receiver)
static Item js_proxy_trap_get(Item proxy, Item key) {
    JsProxyData* pd = js_get_proxy_data(proxy);
    if (!pd) return make_js_undefined();
    if (!js_key_is_symbol(key)) key = js_to_property_key(key);
    if (js_exception_pending) return ItemNull;
    Item trap = js_proxy_get_trap(pd, "get", 3);
    if (js_exception_pending) return ItemNull;
    if (trap.item == ItemNull.item) {
        // no trap — forward to target with receiver for getter this-binding.
        // Stage D: RAII guard preserves any pre-existing receiver (e.g. from
        // prototype chain lookup) or sets the proxy as receiver if absent.
        ScopedProxyReceiver _recv_guard(proxy);
        return js_property_get(PD_TARGET(pd), key);
    }
    // call trap(target, property, receiver)
    Item args[3] = { PD_TARGET(pd), key, proxy };
    Item trap_result = js_call_function(trap, PD_HANDLER(pd), args, 3);
    if (js_exception_pending) return ItemNull;
    // ES2020 §9.5.8 invariant checks
    Item target = PD_TARGET(pd);
    Item target_desc = js_object_get_own_property_descriptor(target, key);
    if (get_type_id(target_desc) == LMD_TYPE_MAP) {
        bool conf_found = false;
        Item conf = js_map_get_fast(target_desc.map, "configurable", 12, &conf_found);
        bool configurable = conf_found ? it2b(js_to_boolean(conf)) : true;
        if (!configurable) {
            // check if data property
            bool wr_found = false;
            Item wr = js_map_get_fast(target_desc.map, "writable", 8, &wr_found);
            if (wr_found && !it2b(js_to_boolean(wr))) {
                // non-configurable non-writable data: trap result must match target value
                bool val_found = false;
                Item tval = js_map_get_fast(target_desc.map, "value", 5, &val_found);
                if (val_found) {
                    extern Item js_strict_equal(Item a, Item b);
                    if (!it2b(js_strict_equal(trap_result, tval))) {
                        return js_throw_type_error("'get' on proxy: property is non-configurable and non-writable on the target, but the trap returned a different value");
                    }
                }
            }
            // check if accessor with undefined getter
            bool get_found = false;
            Item getter = js_map_get_fast(target_desc.map, "get", 3, &get_found);
            if (get_found && (getter.item == ItemNull.item || get_type_id(getter) == LMD_TYPE_UNDEFINED)) {
                if (trap_result.item != ItemNull.item && get_type_id(trap_result) != LMD_TYPE_UNDEFINED) {
                    return js_throw_type_error("'get' on proxy: property is a non-configurable accessor with undefined getter, but the trap returned a truthy value");
                }
            }
        }
    }
    return trap_result;
}

extern "C" Item js_reflect_get_with_receiver(Item target, Item key, Item receiver) {
    if (!js_reflect_target_is_object(target)) {
        return js_throw_type_error("Reflect.get called on non-object");
    }
    if (!js_key_is_symbol(key)) key = js_to_property_key(key);
    if (js_exception_pending) return ItemNull;
    if (receiver.item == ItemNull.item) receiver = target;
    ScopedProxyReceiver _recv_guard(receiver);
    return js_property_get(target, key);
}

static Item js_proxy_trap_set_failure(Item key) {
    if (js_strict_mode && get_type_id(key) == LMD_TYPE_STRING) {
        String* sk = it2s(key);
        js_strict_throw_property_error("set", sk ? sk->chars : NULL, sk ? (int)sk->len : 0);
    } else if (js_strict_mode) {
        js_strict_throw_property_error("set", NULL, 0);
    }
    return (Item){.item = b2it(false)};
}

// Proxy [[Set]](key, value, receiver)
extern "C" Item js_proxy_trap_set_with_receiver(Item proxy, Item key, Item value, Item receiver) {
    JsProxyData* pd = js_get_proxy_data(proxy);
    if (!pd) return (Item){.item = b2it(false)};
    if (!js_key_is_symbol(key)) key = js_to_property_key(key);
    if (js_exception_pending) return ItemNull;
    Item trap = js_proxy_get_trap(pd, "set", 3);
    if (js_exception_pending) return ItemNull;
    if (trap.item == ItemNull.item) {
        return js_reflect_set(PD_TARGET(pd), key, value, receiver);
    }
    // call trap(target, property, value, receiver)
    Item args[4] = { PD_TARGET(pd), key, value, receiver };
    Item result = js_call_function(trap, PD_HANDLER(pd), args, 4);
    if (js_exception_pending) return ItemNull;
    bool bool_result = it2b(js_to_boolean(result));
    if (!bool_result) {
        // ES2020 §9.5.9 step 11: If booleanTrapResult is false, return false.
        // Don't throw — the caller (Reflect.set returns false, assignment in strict mode throws)
        return (Item){.item = b2it(false)};
    }
    // ES2020 §9.5.9 invariant checks
    Item target = PD_TARGET(pd);
    Item target_desc = js_object_get_own_property_descriptor(target, key);
    if (get_type_id(target_desc) == LMD_TYPE_MAP) {
        bool conf_found = false;
        Item conf = js_map_get_fast(target_desc.map, "configurable", 12, &conf_found);
        bool configurable = conf_found ? it2b(js_to_boolean(conf)) : true;
        if (!configurable) {
            // data property: check writable + value match
            bool wr_found = false;
            Item wr = js_map_get_fast(target_desc.map, "writable", 8, &wr_found);
            if (wr_found && !it2b(js_to_boolean(wr))) {
                bool val_found = false;
                Item tval = js_map_get_fast(target_desc.map, "value", 5, &val_found);
                if (val_found) {
                    extern Item js_strict_equal(Item a, Item b);
                    if (!it2b(js_strict_equal(value, tval))) {
                        return js_throw_type_error("'set' on proxy: trap returned truish for property which is non-configurable and non-writable on the target");
                    }
                }
            }
            // accessor with undefined setter
            bool set_found = false;
            Item setter = js_map_get_fast(target_desc.map, "set", 3, &set_found);
            if (set_found && (setter.item == ItemNull.item || get_type_id(setter) == LMD_TYPE_UNDEFINED)) {
                return js_throw_type_error("'set' on proxy: trap returned truish for property which has only a getter on the target");
            }
        }
    }
    return (Item){.item = b2it(true)};
}

static Item js_proxy_trap_set(Item proxy, Item key, Item value) {
    Item receiver = js_proxy_receiver.item ? js_proxy_receiver : proxy;
    Item result = js_proxy_trap_set_with_receiver(proxy, key, value, receiver);
    if (js_exception_pending) return ItemNull;
    if (result.item == (uint64_t)b2it(false)) return js_proxy_trap_set_failure(key);
    return value;
}

// Proxy [[Has]](key)
extern "C" Item js_proxy_trap_has(Item proxy, Item key) {
    JsProxyData* pd = js_get_proxy_data(proxy);
    if (!pd) return (Item){.item = b2it(false)};
    if (!js_key_is_symbol(key)) key = js_to_property_key(key);
    if (js_exception_pending) return ItemNull;
    Item trap = js_proxy_get_trap(pd, "has", 3);
    if (js_exception_pending) return ItemNull;
    if (trap.item == ItemNull.item) {
        // no trap — forward to target using js_in
        return js_in(key, PD_TARGET(pd));
    }
    // call trap(target, property)
    Item args[2] = { PD_TARGET(pd), key };
    Item result = js_call_function(trap, PD_HANDLER(pd), args, 2);
    if (js_exception_pending) return ItemNull;
    bool bool_result = it2b(js_to_boolean(result));
    // ES2020 §9.5.7 invariant checks
    if (!bool_result) {
        Item target = PD_TARGET(pd);
        Item target_desc = js_object_get_own_property_descriptor(target, key);
        if (get_type_id(target_desc) == LMD_TYPE_MAP) {
            // target has own property — check if non-configurable
            bool conf_found = false;
            Item conf = js_map_get_fast(target_desc.map, "configurable", 12, &conf_found);
            bool configurable = conf_found ? it2b(js_to_boolean(conf)) : true;
            if (!configurable) {
                return js_throw_type_error("'has' on proxy: trap returned falsish for property which exists as non-configurable on the target");
            }
            // check extensibility
            bool extensible = it2b(js_to_boolean(js_object_is_extensible(target)));
            if (!extensible) {
                return js_throw_type_error("'has' on proxy: trap returned falsish for property on a non-extensible target");
            }
        }
    }
    return (Item){.item = b2it(bool_result)};
}

// Proxy [[Delete]](key)
extern "C" Item js_proxy_trap_delete(Item proxy, Item key) {
    JsProxyData* pd = js_get_proxy_data(proxy);
    if (!pd) return (Item){.item = b2it(false)};
    if (!js_key_is_symbol(key)) key = js_to_property_key(key);
    if (js_exception_pending) return ItemNull;
    Item trap = js_proxy_get_trap(pd, "deleteProperty", 14);
    if (js_exception_pending) return ItemNull;
    if (trap.item == ItemNull.item) {
        return js_reflect_delete_property(PD_TARGET(pd), key);
    }
    Item args[2] = { PD_TARGET(pd), key };
    Item result = js_call_function(trap, PD_HANDLER(pd), args, 2);
    if (js_exception_pending) return ItemNull;
    bool bool_result = it2b(js_to_boolean(result));
    if (bool_result) {
        // ES2020 §9.5.10 invariant checks
        Item target = PD_TARGET(pd);
        Item target_desc = js_object_get_own_property_descriptor(target, key);
        if (get_type_id(target_desc) == LMD_TYPE_MAP) {
            bool conf_found = false;
            Item conf = js_map_get_fast(target_desc.map, "configurable", 12, &conf_found);
            bool configurable = conf_found ? it2b(js_to_boolean(conf)) : true;
            if (!configurable) {
                return js_throw_type_error("'deleteProperty' on proxy: trap returned truish for property which is non-configurable on the target");
            }
            // non-extensible target: can't delete existing property
            if (!js_is_extensible(target)) {
                return js_throw_type_error("'deleteProperty' on proxy: trap returned truish for property on a non-extensible target");
            }
        }
    }
    return (Item){.item = b2it(bool_result)};
}

// Proxy [[OwnKeys]]()
static Item js_array_like_to_array(Item obj);
static Item js_array_index_key(int64_t index);
static Item js_create_array_iterator_object(Item source, int kind);
static int64_t js_array_iterator_source_length(Item source);
static double js_array_to_integer_or_infinity(Item value);
enum JsArrayIterativeMethodKind {
    JS_ARRAY_ITER_FOR_EACH = 0,
    JS_ARRAY_ITER_MAP = 1,
    JS_ARRAY_ITER_FILTER = 2,
    JS_ARRAY_ITER_SOME = 3,
    JS_ARRAY_ITER_EVERY = 4
};
static Item js_array_generic_includes(Item object, Item* args, int argc);
static Item js_array_generic_index_of(Item object, Item* args, int argc, bool from_right);
static Item js_array_generic_to_reversed(Item object);
static Item js_array_generic_to_sorted(Item object, Item* args, int argc);
static Item js_array_generic_to_spliced(Item object, Item* args, int argc);
static Item js_array_generic_with(Item object, Item* args, int argc);
static Item js_array_generic_sort(Item object, Item* args, int argc);
static Item js_throw_not_callable(const char* method_name);

static int js_typed_array_sort_default_compare(Item x, Item y, bool* ok) {
    if (ok) *ok = true;
    if (js_is_bigint(x) || js_is_bigint(y)) {
        Item lt = js_less_than(x, y);
        if (js_check_exception()) { if (ok) *ok = false; return 0; }
        if (it2b(lt)) return -1;
        Item gt = js_greater_than(x, y);
        if (js_check_exception()) { if (ok) *ok = false; return 0; }
        if (it2b(gt)) return 1;
        return 0;
    }

    double dx = js_get_number(x);
    if (js_check_exception()) { if (ok) *ok = false; return 0; }
    double dy = js_get_number(y);
    if (js_check_exception()) { if (ok) *ok = false; return 0; }
    bool x_nan = dx != dx;
    bool y_nan = dy != dy;
    if (x_nan && y_nan) return 0;
    if (x_nan) return 1;
    if (y_nan) return -1;
    if (dx == 0.0 && dy == 0.0) {
        bool x_neg_zero = signbit(dx);
        bool y_neg_zero = signbit(dy);
        if (x_neg_zero && !y_neg_zero) return -1;
        if (!x_neg_zero && y_neg_zero) return 1;
        return 0;
    }
    if (dx < dy) return -1;
    if (dx > dy) return 1;
    return 0;
}

static int js_typed_array_sort_compare(Item x, Item y, Item comparefn, bool has_comparefn, bool* ok) {
    if (ok) *ok = true;
    if (!has_comparefn) return js_typed_array_sort_default_compare(x, y, ok);

    Item cmp_args[2] = {x, y};
    Item cmp = js_call_function(comparefn, make_js_undefined(), cmp_args, 2);
    if (js_check_exception()) { if (ok) *ok = false; return 0; }
    Item cmp_num = js_to_number(cmp);
    if (js_check_exception()) { if (ok) *ok = false; return 0; }
    double d = js_get_number(cmp_num);
    if (js_check_exception()) { if (ok) *ok = false; return 0; }
    if (d != d || d == 0.0) return 0;
    return d < 0.0 ? -1 : 1;
}

static bool js_typed_array_sort_merge(Item* values, Item* scratch, int start, int mid, int end,
                                      Item comparefn, bool has_comparefn) {
    int left = start;
    int right = mid;
    int out = start;
    while (left < mid && right < end) {
        bool ok = true;
        int cmp = js_typed_array_sort_compare(values[left], values[right],
                                              comparefn, has_comparefn, &ok);
        if (!ok || js_check_exception()) return false;
        if (cmp <= 0) {
            scratch[out++] = values[left++];
        } else {
            scratch[out++] = values[right++];
        }
    }
    while (left < mid) scratch[out++] = values[left++];
    while (right < end) scratch[out++] = values[right++];
    for (int i = start; i < end; i++) values[i] = scratch[i];
    return true;
}

static bool js_typed_array_sort_merge_sort(Item* values, Item* scratch, int start, int end,
                                           Item comparefn, bool has_comparefn) {
    if (end - start <= 1) return true;
    int mid = start + (end - start) / 2;
    if (!js_typed_array_sort_merge_sort(values, scratch, start, mid, comparefn, has_comparefn)) {
        return false;
    }
    if (!js_typed_array_sort_merge_sort(values, scratch, mid, end, comparefn, has_comparefn)) {
        return false;
    }
    return js_typed_array_sort_merge(values, scratch, start, mid, end, comparefn, has_comparefn);
}
