    Item args_array = js_array_new(0);
    for (int i = 0; i < arg_count; i++) {
        js_array_push(args_array, args[i]);
    }
    Item trap_args[3] = { PD_TARGET(pd), this_val, args_array };
    return js_call_function(trap, PD_HANDLER(pd), trap_args, 3);
