static Item js_object_to_string_result(const char* tag, int tag_len) {
    char buf[256];
    int blen = snprintf(buf, sizeof(buf), "[object %.*s]", tag_len, tag);
    return (Item){.item = s2it(heap_create_name(buf, blen))};
}

static bool js_object_to_string_result_from_tag(Item tag, Item* out_result) {
    if (get_type_id(tag) != LMD_TYPE_STRING) return false;
    String* ts = it2s(tag);
    if (!ts) return false;
    *out_result = js_object_to_string_result(ts->chars, (int)ts->len);
    return true;
}

static bool js_object_to_string_shape_tag(Item object, Item receiver,
                                          bool include_proto, Item* out_result) {
    Item tag_key = (Item){.item = s2it(heap_create_name("__sym_4", 7))};
    Item tag = ItemNull;
    JsOwnGetStatus own_status = js_ordinary_get_own(object, tag_key, receiver, &tag);
    if (own_status == JS_OWN_READY) {
        return js_object_to_string_result_from_tag(tag, out_result);
    }
    if (!include_proto) return false;
    tag = js_prototype_lookup(object, tag_key);
    if (tag.item == ItemNull.item) return false;
    return js_object_to_string_result_from_tag(tag, out_result);
}

static bool js_proxy_chain_has_revoked(Item obj) {
    int depth = 0;
    while (js_is_proxy(obj) && depth < 32) {
        JsProxyData* pd = js_get_proxy_data(obj);
        if (!pd || pd->revoked) return true;
        obj = PD_TARGET(pd);
        depth++;
    }
    return false;
}

static Item js_object_to_string_tag_override(Item this_val) {
    TypeId tid = get_type_id(this_val);
    if (this_val.item == ITEM_NULL || this_val.item == ITEM_JS_UNDEFINED ||
        tid == LMD_TYPE_NULL || tid == LMD_TYPE_UNDEFINED) {
        return ItemNull;
    }

    Item receiver = this_val;
    if (tid != LMD_TYPE_MAP && tid != LMD_TYPE_ARRAY && tid != LMD_TYPE_FUNC) {
        receiver = js_to_object(this_val);
    }

    Item tag_key = (Item){.item = s2it(heap_create_name("__sym_4", 7))};
    Item tag = js_property_get(receiver, tag_key);
    if (js_exception_pending) return ItemNull;
    if (get_type_id(tag) != LMD_TYPE_STRING) return ItemNull;

    String* tag_str = it2s(tag);
    if (!tag_str) return ItemNull;
    return js_object_to_string_result(tag_str->chars, (int)tag_str->len);
}

// HasProperty: check own + prototype chain (ES spec [[HasProperty]])
static bool js_has_property(Item obj, Item key) {
    // Proxy [[HasProperty]] trap
    if (js_is_proxy(obj)) {
        Item result = js_proxy_trap_has(obj, key);
        return js_is_truthy(result);
    }
    // String primitives: character indices 0..length-1 are always present
    if (get_type_id(obj) == LMD_TYPE_STRING) {
        String* s = it2s(obj);
        if (!s) return false;
        // Stage A1: ToPropertyKey per spec — Symbol keys must coerce to __sym_N
        // not throw, so the subsequent length/index probe sees a real string.
        Item k = js_to_property_key(key);
        String* ks = it2s(k);
        if (!ks) return false;
        if (ks->len == 6 && strncmp(ks->chars, "length", 6) == 0) return true;
        // parse numeric index
        bool is_num = (ks->len > 0 && ks->len <= 10);
        int64_t idx = 0;
        if (is_num) {
            for (int i = 0; i < (int)ks->len; i++) {
                char c = ks->chars[i];
                if (c < '0' || c > '9') { is_num = false; break; }
                idx = idx * 10 + (c - '0');
            }
            if (is_num && ks->len > 1 && ks->chars[0] == '0') is_num = false;
        }
        if (is_num && idx >= 0 && idx < (int64_t)s->len) return true;
        return false;
    }
    if (get_type_id(obj) == LMD_TYPE_MAP && obj.map &&
        obj.map->map_kind == MAP_KIND_TYPED_ARRAY) {
        double numeric_index = 0.0;
        bool is_negative_zero = false;
        if (js_ta_key_canonical_numeric(key, &numeric_index, &is_negative_zero)) {
            int idx = 0;
            return js_ta_numeric_index_valid(obj, numeric_index, is_negative_zero, &idx);
        }
    }
    if (it2b(js_has_own_property(obj, key))) return true;
    // walk prototype chain — for plain MAPs without explicit __proto__, use js_get_prototype
    // (returns ItemNull for bare object literals) rather than js_get_prototype_of (which returns
    // implicit Object.prototype). This matches pre-v37 HasProperty semantics: an array-like
    // object like {2:2, length:20} doesn't reach Object.prototype, so Object.prototype[k] values
    // captured before getters can fire don't corrupt array-method snapshots.
    Item proto;
    if (get_type_id(obj) == LMD_TYPE_MAP &&
        js_map_kind_is_ordinary_shape(obj.map->map_kind)) {
        proto = js_get_prototype(obj);  // only explicit __proto__; ItemNull for plain object literals
    } else {
        proto = js_get_prototype_of(obj);  // arrays, functions, typed arrays, Objects with __proto__
    }
    int depth = 0;
    while (proto.item != ItemNull.item && get_type_id(proto) != LMD_TYPE_UNDEFINED && depth < 32) {
        if (it2b(js_has_own_property(proto, key))) return true;
        proto = js_get_prototype_of(proto);
        depth++;
    }
    return false;
}

// Convert an array-like object (MAP with length + numeric indices) to an Array
static Item js_array_like_to_array(Item obj) {
    // Get length property — per ES spec, length getter may throw (step 2 of forEach/map/etc.)
    Item length_key = (Item){.item = s2it(heap_create_name("length", 6))};
    Item len_val = js_property_get(obj, length_key);
    // propagate exception from length getter (e.g. Object.defineProperty getter that throws)
    if (js_check_exception()) return ItemNull;
    // ES ToLength(Get(O, "length")) — Symbol throws TypeError per ToNumber.
    if (js_key_is_symbol(len_val)) {
        js_throw_type_error("Cannot convert a Symbol value to a number");
        return ItemNull;
    }
    int len = (int)js_get_number(len_val);
    if (js_check_exception()) return ItemNull;
    if (len < 0) len = 0;
    if (len > 100000) len = 100000; // safety cap
    Item result = js_array_new(len);
    Array* arr = result.array;
    Item hole = lam::hole_sentinel_item();
    for (int i = 0; i < len; i++) {
        char buf[16];
        int blen = snprintf(buf, sizeof(buf), "%d", i);
        Item idx_key = (Item){.item = s2it(heap_create_name(buf, blen))};
        // ES spec: check HasProperty (includes prototype chain) to preserve holes
        bool has = js_has_property(obj, idx_key);
        Item val = hole;
        // v37: For plain MAPs without __proto__, js_has_property/js_property_get
        // skip Object.prototype. If property is missing or undefined here, check
        // Object.prototype manually (unless it's an own setter-only accessor).
        bool plain_map = (get_type_id(obj) == LMD_TYPE_MAP &&
            js_map_kind_is_ordinary_shape(obj.map->map_kind));
        bool is_own_setter_only = false;
        if (plain_map) {
            // Stage A1.5: a setter-only accessor (getter == ItemNull) shadows
            // any inherited property and must produce undefined here, never
            // fall through to Object.prototype. Detect via descriptor kernel.
            JsAccessorPair* _pair = NULL;
            JsOwnDescKind _dk = js_ordinary_get_own_descriptor(
                obj, buf, blen, &_pair, NULL);
            if (_dk == JS_DESC_ACCESSOR && _pair &&
                _pair->getter.item == ItemNull.item) {
                is_own_setter_only = true;
            }
        }
        if (has) {
            val = js_property_get(obj, idx_key);
            if (get_type_id(val) == LMD_TYPE_UNDEFINED && plain_map && !is_own_setter_only) {
                Map* obj_proto = js_resolve_object_prototype();
                if (obj_proto && obj.map != obj_proto) {
                    Item proto_val = js_property_get((Item){.map = obj_proto}, idx_key);
                    if (get_type_id(proto_val) != LMD_TYPE_UNDEFINED) {
                        val = proto_val;
                    }
                }
            }
        } else if (plain_map && !is_own_setter_only) {
            // js_has_property returned false because plain MAPs skip Object.prototype.
            // Check Object.prototype explicitly: if property is present there, treat as inherited.
            Map* obj_proto = js_resolve_object_prototype();
            if (obj_proto && obj.map != obj_proto) {
                Item op_item = (Item){.map = obj_proto};
                if (it2b(js_has_own_property(op_item, idx_key))) {
                    val = js_property_get(op_item, idx_key);
                }
            }
        }
        if (i < arr->capacity) {
            arr->items[i] = val;
            if (i >= arr->length) arr->length = i + 1;
        } else {
            js_array_push_item_direct(arr, val);
        }
    }
    return result;
}

