                Item len_val = js_property_get(this_val, len_key);
                if (js_check_exception()) { js_array_method_real_this = (Item){0}; return ItemNull; }
                Item len_num = js_to_number(len_val);
                if (js_check_exception()) { js_array_method_real_this = (Item){0}; return ItemNull; }
