// v11: Regex support — /pattern/flags as Map objects with compiled RE2
// =============================================================================

#include "js_regex_wrapper.h"
#include "js_regexp_compile.h"
#include "js_bt_regex.h"

// hidden property key for storing regex data pointer
static const char* JS_REGEX_DATA_KEY = "__rd";

// update legacy static state after a successful regex exec
static void js_regexp_update_last_match(String* input_s,
    re2::StringPiece* matches, int num_groups) {
    const char* input_str = input_s ? input_s->chars : "";
    int input_len = input_s ? (int)input_s->len : 0;
    js_regexp_last_match.input = input_s ? input_s : heap_create_name("", 0);
    if (matches[0].data() && input_s && matches[0].data() == input_str &&
        (int)matches[0].size() == input_len) {
        js_regexp_last_match.match = input_s;
    } else {
        js_regexp_last_match.match = matches[0].data()
            ? heap_strcpy((char*)matches[0].data(), (int)matches[0].size())
            : heap_create_name("", 0);
    }
    js_regexp_last_match.match_start = matches[0].data()
        ? (int)(matches[0].data() - input_str) : 0;
    js_regexp_last_match.match_end = js_regexp_last_match.match_start
        + (matches[0].data() ? (int)matches[0].size() : 0);
    int gc = num_groups - 1; // exclude group 0 (full match)
    if (gc > JS_REGEXP_MAX_PAREN) gc = JS_REGEXP_MAX_PAREN;
    if (gc < 0) gc = 0;
    js_regexp_last_match.group_count = gc;
    for (int i = 0; i < gc; i++) {
        int gi = i + 1; // groups[0] is full match, groups[1] is $1
        if (gi < num_groups && matches[gi].data()) {
            if (input_s && matches[gi].data() == input_str &&
                (int)matches[gi].size() == input_len) {
                js_regexp_last_match.groups[i] = input_s;
            } else {
                js_regexp_last_match.groups[i] = heap_strcpy((char*)matches[gi].data(), (int)matches[gi].size());
            }
        } else {
            js_regexp_last_match.groups[i] = heap_create_name("", 0);
        }
    }
    for (int i = gc; i < JS_REGEXP_MAX_PAREN; i++) {
        js_regexp_last_match.groups[i] = heap_create_name("", 0);
    }
}

struct JsRegexData {
    re2::RE2* re2;            // compiled regex (direct, for patterns without assertions)
    JsRegexCompiled* wrapper; // wrapper with post-filters (for patterns with lookaheads/backrefs)
    JsBtRegex* bt;            // spec backtracking matcher (backrefs / hard lookbehind)
    const char* literal_pattern; // simple literal pattern handled without RE2
    int literal_pattern_len;
    int special_property_kind; // +/-: fast Unicode property-repeat kind
    char** named_alias_re2_names;
    int* named_alias_re2_lens;
    char** named_alias_js_names;
    int* named_alias_js_lens;
    int named_alias_count;
    bool global;              // 'g' flag
    bool ignore_case;         // 'i' flag
    bool multiline;           // 'm' flag
    bool sticky;              // 'y' flag (v46)
    bool has_indices;         // 'd' flag
    bool unicode;             // 'u' or 'v' flag: indices are reported as UTF-16 code units
    bool needs_utf16_subject; // legacy surrogate escapes match UTF-16 code units
    bool literal_fast;
};

extern "C" void js_regex_map_heap_destroy(Map* map, gc_native_seen_t* seen_native) {
    if (!map) return;
    Item obj = (Item){.map = map};
    if (js_class_id(obj) != JS_CLASS_REGEXP) return;

    bool found = false;
    Item rd_item = js_map_get_fast_ext(map, JS_REGEX_DATA_KEY, 4, &found);
    if (!found) return;
    TypeId tid = get_type_id(rd_item);
    if (tid != LMD_TYPE_INT && tid != LMD_TYPE_INT64) return;

    int64_t ptr_val = it2i(rd_item);
    if (ptr_val == 0) return;
    JsRegexData* rd = (JsRegexData*)(uintptr_t)ptr_val;
    if (gc_native_seen_seen_or_add(seen_native, rd)) return;

    JsRegexCompiled* wrapper = rd->wrapper;
    if (wrapper) {
        rd->wrapper = nullptr;
        if (rd->re2 == wrapper->re2) rd->re2 = nullptr;
        js_regex_compiled_free(wrapper);
    }
}

// Regex compilation cache: avoids re-compiling the same regex literal in loops.
// Keyed by (pattern_ptr, flags_ptr) — pointer identity from AST nodes.
// Only benefits regex literals (constant AST pointers), not new RegExp() with runtime strings.
struct JsRegexCacheEntry {
    JsRegexData* rd;
    const char* source;          // heap-allocated source string
    int source_len;
    const char* canonical_flags; // heap-allocated canonical flags
    int canonical_flags_len;
    bool dot_all;
    bool has_indices;
    bool has_unicode;
    bool has_unicode_sets;       // Js54: /v flag set
};

static std::unordered_map<uint64_t, JsRegexCacheEntry> g_regex_compile_cache;
static const char* g_regex_property_cache_chars = NULL;
static int g_regex_property_cache_len = 0;
static int g_regex_property_cache_mode = 0;
static bool g_regex_property_cache_result = false;

static inline uint64_t js_regex_cache_key(const char* pattern, const char* flags) {
    return (uint64_t)(uintptr_t)pattern ^ ((uint64_t)(uintptr_t)flags * 2654435761ULL);
}

static void js_regex_cache_entry_release_native(JsRegexCacheEntry* ce) {
    if (!ce || !ce->rd || !ce->rd->wrapper) return;
    JsRegexCompiled* wrapper = ce->rd->wrapper;
    // Batch resets clear stale AST-keyed cache entries before the heap may run
    // RegExp map finalizers; release wrapper native state here and poison the
    // RegExp data pointer so a later finalizer cannot double-free it.
    ce->rd->wrapper = nullptr;
    if (ce->rd->re2 == wrapper->re2) ce->rd->re2 = nullptr;
    js_regex_compiled_free(wrapper);
}

void js_regex_cache_reset() {
    for (auto it = g_regex_compile_cache.begin(); it != g_regex_compile_cache.end(); ++it) {
        js_regex_cache_entry_release_native(&it->second);
    }
    g_regex_compile_cache.clear();
    g_regex_property_cache_chars = NULL;
    g_regex_property_cache_len = 0;
    g_regex_property_cache_mode = 0;
    g_regex_property_cache_result = false;
}

static bool js_regex_unicode_is_other_category(utf8proc_category_t cat) {
    return cat == UTF8PROC_CATEGORY_CC || cat == UTF8PROC_CATEGORY_CF ||
           cat == UTF8PROC_CATEGORY_CS || cat == UTF8PROC_CATEGORY_CO ||
           cat == UTF8PROC_CATEGORY_CN;
}

static std::string js_regex_unicode_category_class(bool unassigned_only, bool negate) {
    static std::string other_class;
    static std::string not_other_class;
    static std::string unassigned_class;
    static std::string not_unassigned_class;
    std::string& cache = unassigned_only
        ? (negate ? not_unassigned_class : unassigned_class)
        : (negate ? not_other_class : other_class);
    if (!cache.empty()) return cache;

    std::string body;
    body.reserve(65536);
    int range_start = -1;
    int range_end = -1;
    for (int cp = 0; cp <= 0x10FFFF; cp++) {
        utf8proc_category_t cat = utf8proc_category((utf8proc_int32_t)cp);
        bool match = unassigned_only
            ? (cat == UTF8PROC_CATEGORY_CN)
            : js_regex_unicode_is_other_category(cat);
        if (match) {
            if (range_start < 0) {
                range_start = cp;
                range_end = cp;
            } else if (cp == range_end + 1) {
                range_end = cp;
            } else {
                char buf[48];
                if (range_start == range_end) {
                    snprintf(buf, sizeof(buf), "\\x{%X}", range_start);
                } else {
                    snprintf(buf, sizeof(buf), "\\x{%X}-\\x{%X}", range_start, range_end);
                }
                body += buf;
                range_start = cp;
                range_end = cp;
            }
        }
    }
    if (range_start >= 0) {
        char buf[48];
        if (range_start == range_end) {
            snprintf(buf, sizeof(buf), "\\x{%X}", range_start);
        } else {
            snprintf(buf, sizeof(buf), "\\x{%X}-\\x{%X}", range_start, range_end);
        }
        body += buf;
    }

    cache.reserve(body.size() + 3);
    cache += negate ? "[^" : "[";
    cache += body;
    cache += "]";
    return cache;
}

static void js_regex_replace_all(std::string& pattern, const char* from, const std::string& to) {
    size_t pos = 0;
    size_t from_len = strlen(from);
    while ((pos = pattern.find(from, pos)) != std::string::npos) {
        pattern.replace(pos, from_len, to);
        pos += to.size();
    }
}

static bool js_regex_match_property_name(const char* name, int len, const char* target) {
    return (int)strlen(target) == len && strncmp(name, target, len) == 0;
}

