// Generic method call with expanded args array (used for obj.method(...spread) calls)
extern "C" Item js_method_call_apply(Item obj, Item method_name, Item args_array) {
    int argc = 0;
    Item* args = NULL;
    if (get_type_id(args_array) == LMD_TYPE_ARRAY && args_array.array->length > 0) {
        argc = (int)args_array.array->length;
        args = LAMBDA_ALLOCA(argc, Item);
        for (int i = 0; i < argc; i++) {
            Item idx = {.item = i2it(i)};
            args[i] = js_array_get(args_array, idx);
        }
    }
    TypeId obj_type = get_type_id(obj);
    if (obj_type == LMD_TYPE_STRING) {
        return js_string_method(obj, method_name, args, argc);
    }
    if (obj_type == LMD_TYPE_ARRAY) {
        return js_array_method(obj, method_name, args, argc);
    }
    if (obj_type == LMD_TYPE_INT || obj_type == LMD_TYPE_FLOAT) {
        return js_number_method(obj, method_name, args, argc);
    }
    if (obj_type == LMD_TYPE_FUNC) {
        Item fn = js_property_access(obj, method_name);
        if (get_type_id(fn) == LMD_TYPE_FUNC) {
            return js_call_function(fn, obj, args, argc);
        }
        return ItemNull;
    }
    return js_map_method(obj, method_name, args, argc);
}

// =============================================================================
// Math Object Methods
// =============================================================================

// backing store for user-defined Math properties (e.g. Math.sumPrecise polyfill)
static Item js_math_object = {.item = ITEM_NULL};

void js_reset_math_object() {
    js_math_object = (Item){.item = ITEM_NULL};
}

static Item js_get_math_object() {
    if (js_math_object.item == ITEM_NULL) {
        // Math inherits from Object.prototype per ES spec (not null prototype)
        js_math_object = js_new_object();
        heap_register_gc_root(&js_math_object.item);
        // Set [[Prototype]] = Object.prototype explicitly so that property
        // lookups (e.g. Object.prototype.value in Math) walk the chain.
        {
            Item obj_ctor = js_get_constructor((Item){.item = s2it(heap_create_name("Object", 6))});
            if (get_type_id(obj_ctor) == LMD_TYPE_FUNC) {
                Item proto_key = (Item){.item = s2it(heap_create_name("prototype", 9))};
                Item op = js_property_get(obj_ctor, proto_key);
                if (get_type_id(op) == LMD_TYPE_MAP) js_set_prototype(js_math_object, op);
            }
        }
        // Mark as Math for Object.prototype.toString
        Item mk = (Item){.item = s2it(heap_create_name("__is_math__", 11))};
        js_property_set(js_math_object, mk, (Item){.item = b2it(true)});
        // v18n: Add Symbol.toStringTag for Math (stored as __sym_4 to match Object.prototype.toString)
        Item tag_k = (Item){.item = s2it(heap_create_name("__sym_4", 7))};
        js_property_set(js_math_object, tag_k, (Item){.item = s2it(heap_create_name("Math", 4))});
        // v41: Mark Symbol.toStringTag as non-writable, non-enumerable (configurable: true per spec)
        js_mark_non_writable(js_math_object, tag_k);
        js_mark_non_enumerable(js_math_object, tag_k);
        // Populate Math constants (non-writable, non-enumerable, non-configurable per spec)
        struct { const char* name; double val; } mc[] = {
            {"PI", M_PI}, {"E", M_E}, {"LN2", M_LN2}, {"LN10", M_LN10},
            {"LOG2E", M_LOG2E}, {"LOG10E", M_LOG10E}, {"SQRT2", M_SQRT2}, {"SQRT1_2", M_SQRT1_2},
        };
        for (int i = 0; i < (int)(sizeof(mc) / sizeof(mc[0])); i++) {
            int nlen = (int)strlen(mc[i].name);
            Item key = (Item){.item = s2it(heap_create_name(mc[i].name, nlen))};
            js_property_set(js_math_object, key, js_make_number(mc[i].val));
            // Mark non-enumerable, non-writable, non-configurable
            js_mark_non_enumerable(js_math_object, key);
            js_mark_non_writable(js_math_object, key);
            js_mark_non_configurable(js_math_object, key);
        }
        // Populate Math methods as function properties for dynamic access (Math[m]).
        js_install_builtin_method_specs(js_math_object, JS_BUILTIN_OWNER_MATH_METHOD);
    }
    return js_math_object;
}

// v18n: externally callable for transpiler to resolve bare `Math` identifier
extern "C" Item js_get_math_object_value() {
    return js_get_math_object();
}

// v18n: JSON and console as global objects for bare identifier resolution
static Item js_json_object = {.item = ITEM_NULL};
void js_reset_json_object() { js_json_object = (Item){.item = ITEM_NULL}; }

extern "C" Item js_get_json_object_value() {
    if (js_json_object.item == ITEM_NULL) {
        // JSON inherits from Object.prototype per ES spec
        js_json_object = js_new_object();
        heap_register_gc_root(&js_json_object.item);
        // Set [[Prototype]] = Object.prototype explicitly (see js_get_math_object).
        {
            Item obj_ctor = js_get_constructor((Item){.item = s2it(heap_create_name("Object", 6))});
            if (get_type_id(obj_ctor) == LMD_TYPE_FUNC) {
                Item proto_key = (Item){.item = s2it(heap_create_name("prototype", 9))};
                Item op = js_property_get(obj_ctor, proto_key);
                if (get_type_id(op) == LMD_TYPE_MAP) js_set_prototype(js_json_object, op);
            }
        }
        Item tag_k = (Item){.item = s2it(heap_create_name("__sym_4", 7))};
        js_property_set(js_json_object, tag_k, (Item){.item = s2it(heap_create_name("JSON", 4))});
        // v41: Mark Symbol.toStringTag as non-writable, non-enumerable (configurable: true per spec)
        js_mark_non_writable(js_json_object, tag_k);
        js_mark_non_enumerable(js_json_object, tag_k);
        // v28: add parse and stringify as callable function properties
        js_install_builtin_method_specs(js_json_object, JS_BUILTIN_OWNER_JSON_METHOD);
    }
    return js_json_object;
}

// =============================================================================
// CSS Namespace Object (CSS.supports, CSS.escape)
// =============================================================================
static Item js_css_namespace_object = {.item = ITEM_NULL};
extern "C" void js_reset_css_namespace_object() { js_css_namespace_object = (Item){.item = ITEM_NULL}; }

extern "C" Item js_get_css_object_value() {
    if (js_css_namespace_object.item != ITEM_NULL) {
        return js_css_namespace_object;
    }

    js_css_namespace_object = js_object_create(ItemNull);
    heap_register_gc_root(&js_css_namespace_object.item);

    // tag as CSS namespace while preserving ordinary shape-backed properties
    if (get_type_id(js_css_namespace_object) == LMD_TYPE_MAP) {
        Map* m = js_css_namespace_object.map;
        m->map_kind = MAP_KIND_CSS_NAMESPACE;
    }

    js_install_builtin_method_specs(js_css_namespace_object, JS_BUILTIN_OWNER_CSS_METHOD);

    // toStringTag
    Item tag_k = (Item){.item = s2it(heap_create_name("__sym_4", 7))};
    js_property_set(js_css_namespace_object, tag_k, (Item){.item = s2it(heap_create_name("CSS", 3))});
    js_mark_non_writable(js_css_namespace_object, tag_k);
    js_mark_non_enumerable(js_css_namespace_object, tag_k);

    return js_css_namespace_object;
}

// =============================================================================
// Intl namespace — minimal Intl.Segmenter (word granularity, ASCII heuristic).
//
// Only enough for the editor's caret word-navigation (`new Intl.Segmenter(
// undefined, { granularity: 'word' }).segment(text)` iterated for isWordLike
// segments). A word char is [A-Za-z0-9_] plus any byte with the high bit set
// (so multi-byte UTF-8 letters stay in the current segment rather than
// splitting the sequence). No locale handling; higher-fidelity Unicode word
// breaking is a follow-up.
// =============================================================================
static inline bool js_intl_segmenter_is_word_byte(unsigned char c) {
    if (c >= 'A' && c <= 'Z') return true;
    if (c >= 'a' && c <= 'z') return true;
    if (c >= '0' && c <= '9') return true;
    if (c == '_') return true;
    if (c >= 0x80) return true;  // UTF-8 continuation / lead byte
    return false;
}

extern "C" Item js_intl_segmenter_segment(Item text_item) {
    Item arr_item = js_array_new(0);
    if (get_type_id(text_item) != LMD_TYPE_STRING &&
        get_type_id(text_item) != LMD_TYPE_SYMBOL) {
        return arr_item;
    }
    String* s = it2s(text_item);
    if (!s || s->len == 0) return arr_item;

    Item idx_key    = (Item){.item = s2it(heap_create_name("index"))};
    Item seg_key    = (Item){.item = s2it(heap_create_name("segment"))};
    Item wordy_key  = (Item){.item = s2it(heap_create_name("isWordLike"))};

    int i = 0;
    while (i < (int)s->len) {
        unsigned char lead = (unsigned char)s->chars[i];
        bool is_word = js_intl_segmenter_is_word_byte(lead);
        int j = i + 1;
        while (j < (int)s->len) {
            unsigned char c = (unsigned char)s->chars[j];
            if (js_intl_segmenter_is_word_byte(c) != is_word) break;
            j++;
        }
        Item entry = js_new_object();
        js_property_set(entry, idx_key, (Item){.item = i2it((int64_t)i)});
        char* seg = (char*)pool_calloc(js_input->pool, j - i + 1);
        memcpy(seg, s->chars + i, j - i);
        seg[j - i] = '\0';
        js_property_set(entry, seg_key, (Item){.item = s2it(heap_create_name(seg, (size_t)(j - i)))});
        js_property_set(entry, wordy_key, (Item){.item = b2it(is_word ? 1 : 0)});
        js_array_push(arr_item, entry);
        i = j;
    }
    return arr_item;
}

extern "C" Item js_intl_segmenter_new(Item /*locale*/, Item /*opts*/) {
    // The spec ties .segment() to the constructor's granularity; we only
    // implement word granularity, so the option is intentionally ignored.
    Item obj = js_new_object();
    js_property_set(obj,
        (Item){.item = s2it(heap_create_name("segment"))},
        js_new_function((void*)js_intl_segmenter_segment, 1));
    return obj;
}

static Item js_intl_object = {.item = ITEM_NULL};
extern "C" void js_reset_intl_object() { js_intl_object = (Item){.item = ITEM_NULL}; }

extern "C" Item js_get_intl_object_value() {
    if (js_intl_object.item != ITEM_NULL) return js_intl_object;
    js_intl_object = js_object_create(ItemNull);
    heap_register_gc_root(&js_intl_object.item);
    js_property_set(js_intl_object,
        (Item){.item = s2it(heap_create_name("Segmenter"))},
        js_new_function((void*)js_intl_segmenter_new, 2));
    Item tag_k = (Item){.item = s2it(heap_create_name("__sym_4", 7))};
    js_property_set(js_intl_object, tag_k,
        (Item){.item = s2it(heap_create_name("Intl", 4))});
    js_mark_non_writable(js_intl_object, tag_k);
    js_mark_non_enumerable(js_intl_object, tag_k);
    return js_intl_object;
}

static Item js_console_object = {.item = ITEM_NULL};
