    Item done_key = (Item){.item = s2it(heap_create_name("done", 4))};
    Item done_item = js_property_get(result, done_key);
    if (js_check_exception()) return true;
    Item done_bool = js_to_boolean(done_item);
    if (js_check_exception()) return true;
