        Item value = js_iterator_step(iterator);
        if (js_check_exception()) return ItemNull;
        if (value.item == JS_ITER_DONE_SENTINEL) return js_make_iter_result(make_js_undefined(), true);
        return js_make_iter_result(value, false);
