static bool js_promise_is_object_like(Item value) {
    TypeId tid = get_type_id(value);
    return tid == LMD_TYPE_MAP || tid == LMD_TYPE_ELEMENT || tid == LMD_TYPE_ARRAY ||
           tid == LMD_TYPE_FUNC || tid == LMD_TYPE_OBJECT || tid == LMD_TYPE_VMAP;
}

static Item js_promise_make_type_error(const char* message, int len) {
    return js_new_error_with_name(
        (Item){.item = s2it(heap_create_name("TypeError", 9))},
        (Item){.item = s2it(heap_create_name(message, len))});
}

static Item js_promise_make_resolving_state(JsPromise* p) {
    Item state = js_new_object();
    int idx = p ? (int)(p - js_promises) : -1;
    js_property_set(state, (Item){.item = s2it(heap_create_name("idx", 3))}, (Item){.item = i2it(idx)});
    js_property_set(state, (Item){.item = s2it(heap_create_name("called", 6))}, (Item){.item = ITEM_FALSE});
    return state;
}

static bool js_promise_resolving_state_claim(Item state_item, int64_t* out_idx) {
    if (get_type_id(state_item) == LMD_TYPE_INT) {
        *out_idx = it2i(state_item);
        return true;
    }
    if (get_type_id(state_item) != LMD_TYPE_MAP) return false;

    Item idx = js_property_get(state_item, (Item){.item = s2it(heap_create_name("idx", 3))});
    if (get_type_id(idx) != LMD_TYPE_INT) return false;

    Item called_key = (Item){.item = s2it(heap_create_name("called", 6))};
    Item called = js_property_get(state_item, called_key);
    if (get_type_id(called) == LMD_TYPE_BOOL && it2b(called)) {
        return false;
    }
    js_property_set(state_item, called_key, (Item){.item = ITEM_TRUE});
    *out_idx = it2i(idx);
    return true;
}

static void js_promise_adopt_native(JsPromise* target, JsPromise* source) {
    if (!target || !source) return;
    if (target == source) {
        Item error = js_promise_make_type_error("Chaining cycle detected for promise", 35);
        js_promise_settle(target, JS_PROMISE_REJECTED, error);
        return;
    }
    Item target_item = js_promise_to_item(target);
    js_promise_mark_rejection_handled(source);
    if (source->state != JS_PROMISE_PENDING) {
        Item handler = js_new_function((void*)(source->state == JS_PROMISE_FULFILLED
            ? js_promise_microtask_resolve : js_promise_microtask_reject), 2);
        Item bound_handler = js_bind_function(handler, ItemNull, &target_item, 1);
        // adopted-promise reactions must execute under the target promise resource.
        js_promise_enqueue_handler(bound_handler, source->result, target_item);
        return;
    }
    if (source->then_count < 8) {
        Item resolve_fn = js_new_function((void*)js_promise_microtask_resolve, 2);
        Item reject_fn = js_new_function((void*)js_promise_microtask_reject, 2);
        source->on_fulfilled[source->then_count] = js_bind_function(resolve_fn, ItemNull, &target_item, 1);
        source->on_rejected[source->then_count] = js_bind_function(reject_fn, ItemNull, &target_item, 1);
        source->next_promise[source->then_count] = target_item;
        source->then_count++;
    }
}

// PromiseResolveThenableJob: invoke the captured then method asynchronously.
// Bound args: promise_item, thenable, then_fn.
static Item js_promise_thenable_job(Item promise_item, Item thenable, Item then_fn) {
    JsPromise* p = js_get_promise(promise_item);
    if (!p || p->state != JS_PROMISE_PENDING) return ItemNull;

    Item resolving_state = js_promise_make_resolving_state(p);
    Item resolve_base = js_new_function((void*)js_resolve_callback, 2);
    Item reject_base = js_new_function((void*)js_reject_callback, 2);
    js_promise_mark_anonymous_builtin(resolve_base);
    js_promise_mark_anonymous_builtin(reject_base);
    Item resolve_fn = js_bind_function(resolve_base, ItemNull, &resolving_state, 1);
    Item reject_fn = js_bind_function(reject_base, ItemNull, &resolving_state, 1);
    js_promise_mark_anonymous_builtin(resolve_fn);
    js_promise_mark_anonymous_builtin(reject_fn);

    Item args[2] = {resolve_fn, reject_fn};
    js_call_function(then_fn, thenable, args, 2);
    if (js_check_exception()) {
        Item error = js_clear_exception();
        Item reject_args[1] = {error};
        js_call_function(reject_fn, ItemNull, reject_args, 1);
    }
    return ItemNull;
}

static void js_promise_enqueue_thenable_job(JsPromise* p, Item thenable, Item then_fn) {
    Item runner_fn = js_new_function((void*)js_promise_thenable_job, 3);
    Item bound_args[3] = {js_promise_to_item(p), thenable, then_fn};
    Item thunk = js_bind_function(runner_fn, ItemNull, bound_args, 3);
    js_enqueue_promise_job(thunk);
}

static void js_promise_resolve_with_value(JsPromise* p, Item value) {
    if (!p || p->state != JS_PROMISE_PENDING) return;

    JsPromise* native_promise = js_get_promise(value);
    if (native_promise) {
        js_promise_adopt_native(p, native_promise);
        return;
    }

    if (js_promise_is_object_like(value)) {
        Item then_key = (Item){.item = s2it(heap_create_name("then", 4))};
        Item then_fn = js_property_get(value, then_key);
        if (js_check_exception()) {
            Item error = js_clear_exception();
            js_promise_settle(p, JS_PROMISE_REJECTED, error);
            return;
        }
        if (get_type_id(then_fn) == LMD_TYPE_FUNC) {
            js_promise_enqueue_thenable_job(p, value, then_fn);
            return;
        }
    }

    js_promise_settle(p, JS_PROMISE_FULFILLED, value);
}

// Microtask runner for promise then() handlers.
// Called with 3 bound args: handler, result, next_promise_item.
// Calls handler(result), then settles next_promise with the return value.
static Item js_promise_microtask_run(Item handler, Item result, Item next_promise_item) {
    if (js_check_exception()) {
        js_clear_exception();
    }
    Item args[1] = {result};
    Item handler_result = js_call_function(handler, ItemNull, args, 1);

    JsPromise* next = js_get_promise(next_promise_item);
    if (js_check_exception()) {
        Item error = js_clear_exception();
        if (next) js_promise_settle(next, JS_PROMISE_REJECTED, error);
        return ItemNull;
    }
    if (handler_result.item == 0) {
        handler_result = make_js_undefined();
    }
    if (next) {
        js_promise_resolve_with_value(next, handler_result);
    }
    return ItemNull;
}

// Microtask runner for finally() handlers.
// Called with 4 bound args: handler, next_promise_item, state_item, original_result.
static Item js_promise_finally_microtask_run(Item handler, Item next_promise_item, Item state_item, Item original_result) {
    JsPromise* next = js_get_promise(next_promise_item);
    Item finally_result = js_call_function(handler, ItemNull, NULL, 0);
    if (js_check_exception()) {
        Item error = js_clear_exception();
        if (next) js_promise_settle(next, JS_PROMISE_REJECTED, error);
        return ItemNull;
    }
    if (!next) return ItemNull;

    Item cleanup_promise = js_promise_resolve(finally_result);
    Item continue_base = js_new_function((void*)js_promise_finally_continue, 4);
    Item continue_args[3] = {next_promise_item, state_item, original_result};
    Item continue_fn = js_bind_function(continue_base, ItemNull, continue_args, 3);

    Item reject_base = js_new_function((void*)js_promise_microtask_reject, 2);
    Item reject_fn = js_bind_function(reject_base, ItemNull, &next_promise_item, 1);

    js_promise_then(cleanup_promise, continue_fn, reject_fn);
    return ItemNull;
}

static Item js_promise_finally_continue(Item next_promise_item, Item state_item, Item original_result, Item ignored) {
    (void)ignored;
    JsPromise* next = js_get_promise(next_promise_item);
    if (next) {
        JsPromiseState orig_state = (JsPromiseState)it2i(state_item);
        js_promise_settle(next, orig_state, original_result);
    }
    return ItemNull;
}

// Bound resolve/reject settle functions for promise chaining.
// When a then() handler returns a pending promise, these are registered as then
// handlers on that returned promise. When it settles, they settle the next promise.
static Item js_promise_microtask_resolve(Item next_promise_item, Item value) {
    JsPromise* next = js_get_promise(next_promise_item);
    if (next) js_promise_resolve_with_value(next, value);
    return ItemNull;
}

static Item js_promise_microtask_reject(Item next_promise_item, Item reason) {
    JsPromise* next = js_get_promise(next_promise_item);
    if (next) js_promise_settle(next, JS_PROMISE_REJECTED, reason);
    return ItemNull;
}

extern "C" Item js_promise_async_function_start(void) {
    Item promise = js_promise_create_pending();
    js_async_hooks_emit_before_resource(promise);
    return promise;
}

extern "C" Item js_promise_async_function_finish(Item promise, Item result, int64_t had_exception) {
    JsPromise* p = js_get_promise(promise);
    js_async_hooks_emit_after_resource(promise);
    if (!p) return result;

    if (had_exception) {
        Item error = js_clear_exception();
        js_promise_settle(p, JS_PROMISE_REJECTED, error);
        return promise;
    }

    JsPromise* returned = js_get_promise(result);
    if (returned && returned != p) {
        Item resolve_base = js_new_function((void*)js_promise_microtask_resolve, 2);
        Item reject_base = js_new_function((void*)js_promise_microtask_reject, 2);
        Item resolve_fn = js_bind_function(resolve_base, ItemNull, &promise, 1);
        Item reject_fn = js_bind_function(reject_base, ItemNull, &promise, 1);
        js_promise_then(result, resolve_fn, reject_fn);
    } else {
        js_promise_resolve_with_value(p, result);
    }
    return promise;
}

// Promise reaction job for a missing handler. It preserves the original state
// while still making pass-through settlement asynchronous.
static Item js_promise_passthrough_run(Item next_promise_item, Item state_item, Item result) {
    JsPromise* next = js_get_promise(next_promise_item);
    if (next) {
        JsPromiseState state = (JsPromiseState)it2i(state_item);
        js_promise_settle(next, state, result);
    }
    return ItemNull;
}

static Item js_promise_domain_run(Item domain, Item job) {
    if (get_type_id(job) != LMD_TYPE_FUNC) return ItemNull;
    return js_domain_call_function(domain, job, ItemNull, NULL, 0);
}

static Item js_promise_async_hook_run(Item resource, Item job) {
    if (get_type_id(job) != LMD_TYPE_FUNC) return ItemNull;
    js_async_hooks_emit_before_resource(resource);
    Item result = js_call_function(job, ItemNull, NULL, 0);
    js_async_hooks_emit_after_resource(resource);
    return result;
}

static Item js_promise_unhandled_check(Item promise_item) {
    JsPromise* p = js_get_promise(promise_item);
    if (!p) return ItemNull;
    p->unhandled_check_scheduled = false;
    if (p->unhandled_epoch != js_promise_unhandled_epoch) return ItemNull;
    if (p->state == JS_PROMISE_REJECTED && !p->rejection_handled && !p->unhandled_reported) {
        p->unhandled_reported = true;
        Item domain = p->reject_domain;
        if (get_type_id(domain) == LMD_TYPE_MAP || get_type_id(domain) == LMD_TYPE_ELEMENT) {
            js_domain_emit_error(domain, p->result);
            if (js_check_exception()) js_clear_exception();
            return ItemNull;
        }
        if (js_promise_unhandled_strict) {
            Item error = p->result;
            TypeId reason_type = get_type_id(error);
            if (reason_type != LMD_TYPE_MAP && reason_type != LMD_TYPE_ELEMENT) {
                const char* msg =
                    "This error originated either by throwing inside of an async function without a catch block, or by rejecting a promise which was not handled with .catch(). The promise rejected with the reason \"null\".";
                error = js_new_error_with_name(
                    (Item){.item = s2it(heap_create_name("UnhandledPromiseRejection", 25))},
                    (Item){.item = s2it(heap_create_name(msg, strlen(msg)))});
                js_property_set(error,
                    (Item){.item = s2it(heap_create_name("code", 4))},
                    (Item){.item = s2it(heap_create_name("ERR_UNHANDLED_REJECTION", 23))});
            }
            js_process_emit2((Item){.item = s2it(heap_create_name("uncaughtException", 17))},
                error,
                (Item){.item = s2it(heap_create_name("unhandledRejection", 18))});
            if (js_check_exception()) js_clear_exception();
        }
        js_process_emit2((Item){.item = s2it(heap_create_name("unhandledRejection", 18))},
            p->result, promise_item);
    }
    return ItemNull;
}

static void js_promise_schedule_unhandled_check(JsPromise* p) {
    if (!p || p->rejection_handled || p->unhandled_check_scheduled || p->unhandled_reported) return;
    p->unhandled_check_scheduled = true;
    p->unhandled_epoch = js_promise_unhandled_epoch;
    if (js_promise_unhandled_queue_count >= 1024) {
        log_error("js-promise: unhandled rejection queue overflow");
        return;
    }
    js_promise_unhandled_queue[js_promise_unhandled_queue_count++] = js_promise_to_item(p);
}

extern "C" void js_promise_flush_unhandled_checks(void) {
    int count = js_promise_unhandled_queue_count;
    if (count <= 0) return;
    js_promise_unhandled_queue_count = 0;
    for (int i = 0; i < count; i++) {
        Item promise_item = js_promise_unhandled_queue[i];
        js_promise_unhandled_queue[i] = ItemNull;
        js_promise_unhandled_check(promise_item);
    }
}

static void js_promise_mark_rejection_handled(JsPromise* p) {
    if (!p || p->rejection_handled) return;
    p->rejection_handled = true;
    if (p->unhandled_reported) {
        js_process_emit((Item){.item = s2it(heap_create_name("rejectionHandled", 16))},
            js_promise_to_item(p));
        if (js_check_exception()) {
            Item error = js_clear_exception();
            js_process_emit((Item){.item = s2it(heap_create_name("uncaughtException", 17))}, error);
        }
    }
}

// Enqueue a promise handler as a microtask with proper chaining.
// Creates a bound thunk: js_promise_microtask_run(handler, result, next_promise_item)
static void js_promise_enqueue_handler(Item handler, Item result, Item next_promise_item) {
    Item runner_fn = js_new_function((void*)js_promise_microtask_run, 3);
    Item bound_args[3] = {handler, result, next_promise_item};
    Item thunk = js_bind_function(runner_fn, ItemNull, bound_args, 3);
    Item resource = get_type_id(next_promise_item) == LMD_TYPE_MAP
        ? next_promise_item : js_async_hooks_get_current_resource();
    Item hook_runner = js_new_function((void*)js_promise_async_hook_run, 2);
    Item hook_args[2] = {resource, thunk};
    thunk = js_bind_function(hook_runner, ItemNull, hook_args, 2);
    Item previous = js_async_hooks_enter_resource(resource);
    js_enqueue_promise_job(thunk);
    js_async_hooks_restore_resource(previous);
}

static void js_promise_enqueue_handler_domain(Item handler, Item result, Item next_promise_item, Item domain) {
    Item runner_fn = js_new_function((void*)js_promise_microtask_run, 3);
    Item bound_args[3] = {handler, result, next_promise_item};
    Item thunk = js_bind_function(runner_fn, ItemNull, bound_args, 3);
    if (get_type_id(domain) == LMD_TYPE_MAP || get_type_id(domain) == LMD_TYPE_ELEMENT) {
        Item domain_runner = js_new_function((void*)js_promise_domain_run, 2);
        Item domain_args[2] = {domain, thunk};
        thunk = js_bind_function(domain_runner, ItemNull, domain_args, 2);
    }
    Item resource = get_type_id(next_promise_item) == LMD_TYPE_MAP
        ? next_promise_item : js_async_hooks_get_current_resource();
    Item hook_runner = js_new_function((void*)js_promise_async_hook_run, 2);
    Item hook_args[2] = {resource, thunk};
    thunk = js_bind_function(hook_runner, ItemNull, hook_args, 2);
    // promise jobs are enqueued while the settling promise is active, so stamp
    // the queue entry with the reaction promise resource instead.
    Item previous = js_async_hooks_enter_resource(resource);
    js_enqueue_promise_job(thunk);
    js_async_hooks_restore_resource(previous);
}

// Enqueue a finally handler as a microtask.
static void js_promise_enqueue_finally(Item handler, Item next_promise_item, JsPromiseState state, Item result, Item domain) {
    Item runner_fn = js_new_function((void*)js_promise_finally_microtask_run, 4);
    Item bound_args[4] = {handler, next_promise_item, (Item){.item = i2it((int64_t)state)}, result};
    Item thunk = js_bind_function(runner_fn, ItemNull, bound_args, 4);
    if (get_type_id(domain) == LMD_TYPE_MAP || get_type_id(domain) == LMD_TYPE_ELEMENT) {
        Item domain_runner = js_new_function((void*)js_promise_domain_run, 2);
        Item domain_args[2] = {domain, thunk};
        thunk = js_bind_function(domain_runner, ItemNull, domain_args, 2);
    }
    Item resource = get_type_id(next_promise_item) == LMD_TYPE_MAP
        ? next_promise_item : js_async_hooks_get_current_resource();
    Item hook_runner = js_new_function((void*)js_promise_async_hook_run, 2);
    Item hook_args[2] = {resource, thunk};
    thunk = js_bind_function(hook_runner, ItemNull, hook_args, 2);
    Item previous = js_async_hooks_enter_resource(resource);
    js_enqueue_promise_job(thunk);
    js_async_hooks_restore_resource(previous);
}

static void js_promise_enqueue_passthrough(Item next_promise_item, JsPromiseState state, Item result, Item domain) {
    Item runner_fn = js_new_function((void*)js_promise_passthrough_run, 3);
    Item bound_args[3] = {next_promise_item, (Item){.item = i2it((int64_t)state)}, result};
    Item thunk = js_bind_function(runner_fn, ItemNull, bound_args, 3);
    if (get_type_id(domain) == LMD_TYPE_MAP || get_type_id(domain) == LMD_TYPE_ELEMENT) {
        Item domain_runner = js_new_function((void*)js_promise_domain_run, 2);
        Item domain_args[2] = {domain, thunk};
        thunk = js_bind_function(domain_runner, ItemNull, domain_args, 2);
    }
    Item resource = get_type_id(next_promise_item) == LMD_TYPE_MAP
        ? next_promise_item : js_async_hooks_get_current_resource();
    Item hook_runner = js_new_function((void*)js_promise_async_hook_run, 2);
    Item hook_args[2] = {resource, thunk};
    thunk = js_bind_function(hook_runner, ItemNull, hook_args, 2);
    Item previous = js_async_hooks_enter_resource(resource);
    js_enqueue_promise_job(thunk);
    js_async_hooks_restore_resource(previous);
}

static void js_promise_settle(JsPromise* p, JsPromiseState state, Item result) {
    if (p->state != JS_PROMISE_PENDING) return; // already settled

    p->state = state;
    p->result = result;
    Item promise_resource = js_promise_to_item(p);
    js_async_hooks_emit_promise_resolve_resource(promise_resource);
    if (state == JS_PROMISE_REJECTED) {
        p->reject_domain = js_domain_get_current();
    }

    // Schedule handlers as microtasks (per ECMAScript spec)
    for (int i = 0; i < p->then_count; i++) {
        Item handler = (state == JS_PROMISE_FULFILLED) ? p->on_fulfilled[i] : p->on_rejected[i];
        Item next_item = p->next_promise[i];
        Item domain = p->reaction_domain[i];

        if (p->is_finally[i]) {
            // finally handler: called with 0 args, passes through original result
            if (get_type_id(handler) == LMD_TYPE_FUNC) {
                js_promise_enqueue_finally(handler, next_item, state, result, domain);
            } else {
                js_promise_enqueue_passthrough(next_item, state, result, domain);
            }
        } else if (get_type_id(handler) == LMD_TYPE_FUNC) {
            if (get_type_id(next_item) == LMD_TYPE_MAP) {
                // has a chained next promise — enqueue with chaining
                js_promise_enqueue_handler_domain(handler, result, next_item, domain);
            } else {
                // direct handler (e.g. from chaining resolution), no next promise
                js_promise_enqueue_handler_domain(handler, result, ItemNull, domain);
            }
        } else {
            // no handler for this state — propagate through a Promise reaction job
            js_promise_enqueue_passthrough(next_item, state, result, domain);
        }
    }

    if (state == JS_PROMISE_REJECTED) {
        js_promise_schedule_unhandled_check(p);
    }
}

// Resolve/reject callbacks for promise executors.
// Each callback is bound (via js_bind_function) to its promise index,
// so these work even when called asynchronously (e.g. in setTimeout).
static Item js_resolve_callback(Item promise_idx_item, Item value) {
    int64_t idx = -1;
    if (!js_promise_resolving_state_claim(promise_idx_item, &idx)) return make_js_undefined();
    if (idx >= 0 && idx < js_promise_count) {
        js_promise_resolve_with_value(&js_promises[idx], value);
    }
    return make_js_undefined();
}

static Item js_reject_callback(Item promise_idx_item, Item reason) {
    int64_t idx = -1;
    if (!js_promise_resolving_state_claim(promise_idx_item, &idx)) return make_js_undefined();
    if (idx >= 0 && idx < js_promise_count) {
        js_promise_settle(&js_promises[idx], JS_PROMISE_REJECTED, reason);
    }
    return make_js_undefined();
}

extern "C" Item js_promise_create(Item executor) {
    // ES2020 §25.6.3.1 step 2: If IsCallable(executor) is false, throw a TypeError
    if (get_type_id(executor) != LMD_TYPE_FUNC) {
        return js_throw_type_error("Promise resolver is not a function");
    }
    JsPromise* p = js_alloc_promise();
    if (!p) return ItemNull;
    // async_hooks observes Promise creation before executor-side resolution.
    Item promise_item = js_promise_to_item(p);

    {
        // Create resolve/reject functions bound to this promise's index
        Item resolving_state = js_promise_make_resolving_state(p);
        Item resolve_base = js_new_function((void*)js_resolve_callback, 2);
        Item reject_base = js_new_function((void*)js_reject_callback, 2);
        js_promise_mark_anonymous_builtin(resolve_base);
        js_promise_mark_anonymous_builtin(reject_base);
        Item resolve_fn = js_bind_function(resolve_base, ItemNull, &resolving_state, 1);
        Item reject_fn = js_bind_function(reject_base, ItemNull, &resolving_state, 1);
        js_promise_mark_anonymous_builtin(resolve_fn);
        js_promise_mark_anonymous_builtin(reject_fn);

        Item args[2] = {resolve_fn, reject_fn};
        js_call_function(executor, make_js_undefined(), args, 2);
        if (js_check_exception()) {
            Item error = js_clear_exception();
            js_promise_settle(p, JS_PROMISE_REJECTED, error);
        }
    }

    return promise_item;
}

extern "C" Item js_promise_resolve(Item value) {
    // If value is already a promise, return it
    JsPromise* existing = js_get_promise(value);
    if (existing) return value;

    JsPromise* p = js_alloc_promise();
    if (!p) return ItemNull;
    // PromiseResolve creates the wrapper resource before applying thenables.
    Item promise_item = js_promise_to_item(p);
    js_promise_resolve_with_value(p, value);
    return promise_item;
}

extern "C" Item js_promise_create_pending(void) {
    JsPromise* p = js_alloc_promise();
    if (!p) return ItemNull;
    return js_promise_to_item(p);
}

extern "C" void js_promise_fulfill_existing(Item promise, Item value) {
    JsPromise* p = js_get_promise(promise);
    if (!p) return;
    js_promise_resolve_with_value(p, value);
}

extern "C" bool js_promise_is(Item promise) {
    return js_get_promise(promise) != NULL;
}

extern "C" void js_promise_reject_existing(Item promise, Item reason) {
    JsPromise* p = js_get_promise(promise);
    if (!p) return;
    js_promise_settle(p, JS_PROMISE_REJECTED, reason);
}

extern "C" Item js_promise_reject(Item reason) {
    JsPromise* p = js_alloc_promise();
    if (!p) return ItemNull;
    // Promise.reject has a PROMISE resource even though it settles immediately.
    Item promise_item = js_promise_to_item(p);
    js_promise_settle(p, JS_PROMISE_REJECTED, reason);
    return promise_item;
}

static bool js_promise_is_builtin_promise_constructor(Item constructor) {
    if (get_type_id(constructor) != LMD_TYPE_FUNC) return false;
    JsFunction* fn = (JsFunction*)constructor.function;
    if (!fn || !fn->name) return false;
    const char* name = fn->name->chars;
    int len = (int)fn->name->len;
    if (len > 6 && strncmp(name, "bound ", 6) == 0) {
        name += 6;
        len -= 6;
    }
    return len == 7 && strncmp(name, "Promise", 7) == 0;
}

static void js_promise_mark_anonymous_builtin(Item fn_item) {
    if (get_type_id(fn_item) != LMD_TYPE_FUNC) return;
    JsFunction* fn = (JsFunction*)fn_item.function;
    if (!fn) return;
    // Js56 P5: js_new_function caches by func_ptr, so the resolve/reject base
    // functions are shared across all `new Promise(...)` invocations. Marking
    // sets `name`="" non-writable; doing it twice on the same shared function
    // throws "Cannot assign to read only property 'name'". Skip the redundant
    // marking on the UNBOUND cached callback only — `js_bind_function` produces
    // a fresh `JsFunction*` per Promise (each with its own name slot), so bound
    // functions must still be marked. (E1 cluster: 7 tests in
    // language/module-code/top-level-await/syntax/*-await-expr-new-expr;
    // regression to avoid: Promise/{resolve,reject}-function-name and bound
    // 'name' = "" mismatch.)
    bool is_bound = (fn->flags & JS_FUNC_FLAG_HAS_BOUND_THIS) != 0;
    if (!is_bound && fn->name && fn->name->len == 0) return;
    fn->name = heap_create_name("", 0);
    fn->flags |= JS_FUNC_FLAG_ARROW;
    Item name_key = (Item){.item = s2it(heap_create_name("name", 4))};
    Item empty_name = (Item){.item = s2it(heap_create_name("", 0))};
    js_func_init_property(fn_item, name_key, empty_name);
    js_mark_non_writable(fn_item, name_key);
    js_mark_non_enumerable(fn_item, name_key);
}

static Item js_promise_default_constructor(void) {
    return js_get_constructor((Item){.item = s2it(heap_create_name("Promise", 7))});
}

static Item js_promise_species_constructor(Item promise) {
    Item default_constructor = js_promise_default_constructor();
    Item constructor_key = (Item){.item = s2it(heap_create_name("constructor", 11))};
    Item constructor = js_property_get(promise, constructor_key);
    if (js_check_exception()) return ItemNull;
    if (get_type_id(constructor) == LMD_TYPE_UNDEFINED) {
        return default_constructor;
    }
    if (!js_promise_is_object_like(constructor)) {
        return js_throw_type_error("Promise species constructor is not an object");
    }

    Item species_key = (Item){.item = s2it(heap_create_name("__sym_6", 7))};
    Item species = js_property_get(constructor, species_key);
    if (js_check_exception()) return ItemNull;
    TypeId species_type = get_type_id(species);
    if (species_type == LMD_TYPE_UNDEFINED || species_type == LMD_TYPE_NULL ||
        species.item == ItemNull.item) {
        return default_constructor;
    }
    if (!js_is_constructor_internal(species)) {
        return js_throw_type_error("Promise species is not a constructor");
    }
    return species;
}

static Item js_promise_invoke_then(Item promise, Item on_fulfilled, Item on_rejected) {
    TypeId promise_type = get_type_id(promise);
    if (promise_type == LMD_TYPE_NULL || promise_type == LMD_TYPE_UNDEFINED ||
        promise.item == ItemNull.item) {
        return js_throw_type_error("Promise then lookup called on null or undefined");
    }
    Item get_base = js_promise_is_object_like(promise) ? promise : js_to_object(promise);
    Item then_key = (Item){.item = s2it(heap_create_name("then", 4))};
    Item then_fn = js_property_get(get_base, then_key);
    if (js_check_exception()) return ItemNull;
    Item args[2] = {on_fulfilled, on_rejected};
    return js_call_function(then_fn, promise, args, 2);
}

static Item js_promise_finally_value_thunk(Item value, Item ignored) {
    (void)ignored;
    return value;
}

static Item js_promise_finally_throw_thunk(Item reason, Item ignored) {
    (void)ignored;
    js_throw_value(reason);
    return ItemNull;
}

static Item js_promise_make_finally_continuation(void* fn_ptr, Item captured) {
    Item base = js_new_function(fn_ptr, 2);
    js_promise_mark_anonymous_builtin(base);
    Item bound = js_bind_function(base, ItemNull, &captured, 1);
    js_promise_mark_anonymous_builtin(bound);
    return bound;
}

static Item js_promise_then_finally(Item on_finally, Item constructor, Item value) {
    Item finally_result = js_call_function(on_finally, make_js_undefined(), NULL, 0);
    if (js_check_exception()) return ItemNull;
    Item result = js_promise_resolve_with_constructor(constructor, finally_result);
    if (js_check_exception()) return ItemNull;
    Item thunk = js_promise_make_finally_continuation((void*)js_promise_finally_value_thunk, value);
    return js_promise_invoke_then(result, thunk, make_js_undefined());
}

static Item js_promise_catch_finally(Item on_finally, Item constructor, Item reason) {
    Item finally_result = js_call_function(on_finally, make_js_undefined(), NULL, 0);
    if (js_check_exception()) return ItemNull;
    Item result = js_promise_resolve_with_constructor(constructor, finally_result);
    if (js_check_exception()) return ItemNull;
    Item thunk = js_promise_make_finally_continuation((void*)js_promise_finally_throw_thunk, reason);
    return js_promise_invoke_then(result, thunk, make_js_undefined());
}

static Item js_promise_make_finally_wrapper(void* fn_ptr, Item on_finally, Item constructor) {
    Item base = js_new_function(fn_ptr, 3);
    js_promise_mark_anonymous_builtin(base);
    Item bound_args[2] = {on_finally, constructor};
    Item bound = js_bind_function(base, ItemNull, bound_args, 2);
    js_promise_mark_anonymous_builtin(bound);
    return bound;
}

static bool js_promise_capability_slot_is_undefined(Item value) {
    return value.item == ItemNull.item || value.item == ItemError.item ||
           value.item == ITEM_JS_UNDEFINED || get_type_id(value) == LMD_TYPE_UNDEFINED;
}

static Item js_promise_capability_normalize_arg(Item value) {
    return js_promise_capability_slot_is_undefined(value) ? make_js_undefined() : value;
}

// NewPromiseCapability executor. Bound arg: holder object.
static Item js_promise_capability_executor(Item holder, Item resolve, Item reject) {
    resolve = js_promise_capability_normalize_arg(resolve);
    reject = js_promise_capability_normalize_arg(reject);
    Item resolve_key = (Item){.item = s2it(heap_create_name("resolve", 7))};
    Item reject_key = (Item){.item = s2it(heap_create_name("reject", 6))};
    Item existing_resolve = js_property_get(holder, resolve_key);
    if (!js_promise_capability_slot_is_undefined(existing_resolve)) {
        return js_throw_type_error("Promise capability executor already called");
    }
    Item existing_reject = js_property_get(holder, reject_key);
    if (!js_promise_capability_slot_is_undefined(existing_reject)) {
        return js_throw_type_error("Promise capability executor already called");
    }
    js_property_set(holder, resolve_key, resolve);
    js_property_set(holder, reject_key, reject);
    return make_js_undefined();
}

static Item js_promise_new_capability(Item constructor, Item* out_resolve, Item* out_reject) {
    Item holder = js_new_object();
    js_property_set(holder, (Item){.item = s2it(heap_create_name("resolve", 7))}, make_js_undefined());
    js_property_set(holder, (Item){.item = s2it(heap_create_name("reject", 6))}, make_js_undefined());
    Item capture_base = js_new_function((void*)js_promise_capability_executor, 3);
    js_promise_mark_anonymous_builtin(capture_base);
    Item executor = js_bind_function(capture_base, ItemNull, &holder, 1);
    js_promise_mark_anonymous_builtin(executor);
    Item args[1] = {executor};
    Item promise = js_new_from_class_object(constructor, args, 1);
    if (js_check_exception()) return ItemNull;

    Item resolve = js_property_get(holder, (Item){.item = s2it(heap_create_name("resolve", 7))});
    Item reject = js_property_get(holder, (Item){.item = s2it(heap_create_name("reject", 6))});
    if (get_type_id(resolve) != LMD_TYPE_FUNC || get_type_id(reject) != LMD_TYPE_FUNC) {
        js_throw_type_error("Promise capability executor did not capture resolving functions");
        return ItemNull;
    }
    *out_resolve = resolve;
    *out_reject = reject;
    return promise;
}

static Item js_promise_resolve_with_constructor(Item constructor, Item value) {
    JsPromise* existing = js_get_promise(value);
    if (existing) {
        Item ctor_key = (Item){.item = s2it(heap_create_name("constructor", 11))};
        Item value_ctor = js_property_get(value, ctor_key);
        if (js_check_exception()) return ItemNull;
        if (value_ctor.item == constructor.item) return value;
    }

    if (js_promise_is_builtin_promise_constructor(constructor)) {
        if (!existing) return js_promise_resolve(value);
        JsPromise* p = js_alloc_promise();
        if (!p) return ItemNull;
        Item promise_item = js_promise_to_item(p);
        js_promise_resolve_with_value(p, value);
        return promise_item;
    }

    Item resolve = ItemNull;
    Item reject = ItemNull;
    Item promise = js_promise_new_capability(constructor, &resolve, &reject);
    if (js_check_exception()) return ItemNull;
    (void)reject;
    Item args[1] = {value};
    js_call_function(resolve, ItemNull, args, 1);
    if (js_check_exception()) return ItemNull;
    return promise;
}

static Item js_promise_reject_with_constructor(Item constructor, Item reason) {
    if (js_promise_is_builtin_promise_constructor(constructor)) {
        return js_promise_reject(reason);
    }

    Item resolve = ItemNull;
    Item reject = ItemNull;
    Item promise = js_promise_new_capability(constructor, &resolve, &reject);
    if (js_check_exception()) return ItemNull;
    (void)resolve;
    Item args[1] = {reason};
    js_call_function(reject, ItemNull, args, 1);
    if (js_check_exception()) return ItemNull;
    return promise;
}

static Item js_promise_capability_forward_resolve(Item resolve, Item reject, Item value) {
    Item args[1] = {value};
    js_call_function(resolve, ItemNull, args, 1);
    if (js_check_exception()) {
        Item error = js_clear_exception();
        Item reject_args[1] = {error};
        js_call_function(reject, ItemNull, reject_args, 1);
        if (js_check_exception()) js_clear_exception();
    }
    return make_js_undefined();
}

static Item js_promise_capability_forward_reject(Item reject, Item reason) {
    Item args[1] = {reason};
    js_call_function(reject, ItemNull, args, 1);
    if (js_check_exception()) js_clear_exception();
    return make_js_undefined();
}

static Item js_promise_call_capability_resolve(Item resolve, Item reject, Item value) {
    Item args[1] = {value};
    js_call_function(resolve, ItemNull, args, 1);
    if (js_check_exception()) {
        Item error = js_clear_exception();
        Item reject_args[1] = {error};
        js_call_function(reject, ItemNull, reject_args, 1);
        if (js_check_exception()) js_clear_exception();
    }
    return make_js_undefined();
}

static Item js_promise_call_capability_reject(Item reject, Item reason) {
    Item args[1] = {reason};
    js_call_function(reject, ItemNull, args, 1);
    if (js_check_exception()) js_clear_exception();
    return make_js_undefined();
}

static void js_promise_forward_native_to_capability(Item native_promise, Item resolve, Item reject) {
    Item resolve_base = js_new_function((void*)js_promise_capability_forward_resolve, 3);
    Item resolve_args[2] = {resolve, reject};
    Item resolve_fn = js_bind_function(resolve_base, ItemNull, resolve_args, 2);

    Item reject_base = js_new_function((void*)js_promise_capability_forward_reject, 2);
    Item reject_fn = js_bind_function(reject_base, ItemNull, &reject, 1);

    js_promise_then(native_promise, resolve_fn, reject_fn);
}

static bool js_promise_resolve_elements_with_constructor(Item constructor, Item resolve_method,
    Item arr_item, Item* out_array, Item reject) {
    Array* arr = arr_item.array;
    Item resolved = js_array_new(arr->length);
    for (int i = 0; i < arr->length; i++) {
        Item args[1] = {arr->items[i]};
        Item next = js_call_function(resolve_method, constructor, args, 1);
        if (js_check_exception()) {
            Item error = js_clear_exception();
            js_promise_call_capability_reject(reject, error);
            return false;
        }
        resolved.array->items[i] = next;
    }
    *out_array = resolved;
    return true;
}

static Item js_promise_combinator_iterable_with_constructor(
    Item constructor, Item iterable, int kind, Item promise, Item resolve, Item reject) {
    Item resolve_method = js_property_get(constructor, (Item){.item = s2it(heap_create_name("resolve", 7))});
    if (js_check_exception()) {
        Item error = js_clear_exception();
        js_promise_call_capability_reject(reject, error);
        return promise;
    }
    if (get_type_id(resolve_method) != LMD_TYPE_FUNC) {
        Item error = js_promise_make_type_error("Promise resolve is not callable", 31);
        js_promise_call_capability_reject(reject, error);
        return promise;
    }

    Item iterator = js_get_iterator(iterable);
    if (js_check_exception()) {
        Item error = js_clear_exception();
        js_promise_call_capability_reject(reject, error);
        return promise;
    }

    JsPromise* native_result = nullptr;
    Item native_item = ItemNull;
    if (kind != 3) {
        native_result = js_alloc_promise();
        if (!native_result) return promise;
        native_item = js_promise_to_item(native_result);
        js_promise_forward_native_to_capability(native_item, resolve, reject);
    }

    Item counter = ItemNull;
    Item values_arr = ItemNull;
    Item called_arr = ItemNull;
    if (kind != 3) {
        counter = js_new_object();
        js_property_set(counter, (Item){.item = s2it(heap_create_name("remaining", 9))}, (Item){.item = i2it(1)});
        values_arr = js_array_new(0);
        called_arr = js_array_new(0);
        const char* values_name = (kind == 2) ? "errors" : "results";
        int values_len = (kind == 2) ? 6 : 7;
        js_property_set(counter, (Item){.item = s2it(heap_create_name(values_name, values_len))}, values_arr);
        js_property_set(counter, (Item){.item = s2it(heap_create_name("called", 6))}, called_arr);
    }

    int index = 0;
    while (true) {
        Item elem = js_iterator_step(iterator);
        if (js_check_exception()) {
            Item error = js_clear_exception();
            js_promise_call_capability_reject(reject, error);
            return promise;
        }
        if (elem.item == JS_ITER_DONE_SENTINEL) break;

        Item args[1] = {elem};
        Item next_promise = js_call_function(resolve_method, constructor, args, 1);
        if (js_check_exception()) {
            Item error = js_clear_exception();
            js_iterator_close(iterator);
            if (js_check_exception()) js_clear_exception();
            js_promise_call_capability_reject(reject, error);
            return promise;
        }

        if (kind == 3) {
            Item error = ItemNull;
            if (!js_invoke_promise_then(next_promise, resolve, reject, &error)) {
                js_iterator_close(iterator);
                if (js_check_exception()) js_clear_exception();
                js_promise_call_capability_reject(reject, error);
                return promise;
            }
            continue;
        }

        js_array_push_item_direct(values_arr.array, make_js_undefined());
        js_array_push_item_direct(called_arr.array, (Item){.item = ITEM_FALSE});
        int remaining = (int)it2i(js_property_get(counter, (Item){.item = s2it(heap_create_name("remaining", 9))}));
        js_property_set(counter, (Item){.item = s2it(heap_create_name("remaining", 9))}, (Item){.item = i2it(remaining + 1)});

        Item fulfill_fn = ItemNull;
        Item reject_fn = ItemNull;
        if (kind == 0) {
            Item fulfill_handler = js_new_function((void*)js_all_resolve_element, 4);
            Item fulfill_args[3] = {counter, (Item){.item = i2it(index)}, native_item};
            fulfill_fn = js_bind_function(fulfill_handler, ItemNull, fulfill_args, 3);
            js_promise_mark_anonymous_builtin(fulfill_fn);

            reject_fn = reject;
        } else if (kind == 1) {
            Item fulfill_handler = js_new_function((void*)js_settled_fulfill_element, 4);
            Item fulfill_args[3] = {counter, (Item){.item = i2it(index)}, native_item};
            fulfill_fn = js_bind_function(fulfill_handler, ItemNull, fulfill_args, 3);
            js_promise_mark_anonymous_builtin(fulfill_fn);

            Item reject_handler = js_new_function((void*)js_settled_reject_element, 4);
            Item reject_args[3] = {counter, (Item){.item = i2it(index)}, native_item};
            reject_fn = js_bind_function(reject_handler, ItemNull, reject_args, 3);
            js_promise_mark_anonymous_builtin(reject_fn);
        } else {
            Item fulfill_handler = js_new_function((void*)js_any_fulfill_element, 4);
            Item fulfill_args[3] = {counter, (Item){.item = i2it(index)}, native_item};
            fulfill_fn = js_bind_function(fulfill_handler, ItemNull, fulfill_args, 3);
            js_promise_mark_anonymous_builtin(fulfill_fn);

            Item reject_handler = js_new_function((void*)js_any_reject_element, 4);
            Item reject_args[3] = {counter, (Item){.item = i2it(index)}, native_item};
            reject_fn = js_bind_function(reject_handler, ItemNull, reject_args, 3);
            js_promise_mark_anonymous_builtin(reject_fn);
        }

        Item error = ItemNull;
        if (!js_invoke_promise_then(next_promise, fulfill_fn, reject_fn, &error)) {
            js_iterator_close(iterator);
            if (js_check_exception()) js_clear_exception();
            js_promise_call_capability_reject(reject, error);
            return promise;
        }
        index++;
    }

    if (kind != 3) {
        int remaining = (int)it2i(js_property_get(counter, (Item){.item = s2it(heap_create_name("remaining", 9))})) - 1;
        js_property_set(counter, (Item){.item = s2it(heap_create_name("remaining", 9))}, (Item){.item = i2it(remaining)});
        if (remaining == 0) {
            if (kind == 2) js_promise_settle(native_result, JS_PROMISE_REJECTED, js_promise_make_aggregate_error(values_arr));
            else js_promise_settle(native_result, JS_PROMISE_FULFILLED, values_arr);
        }
    }

    return promise;
}

static Item js_promise_combinator_with_constructor(Item constructor, Item iterable, int kind) {
    Item resolve = ItemNull;
    Item reject = ItemNull;
    Item promise = js_promise_new_capability(constructor, &resolve, &reject);
    if (js_check_exception()) return ItemNull;

    if (!js_promise_is_builtin_promise_constructor(constructor)) {
        return js_promise_combinator_iterable_with_constructor(
            constructor, iterable, kind, promise, resolve, reject);
    }

    if (get_type_id(iterable) != LMD_TYPE_ARRAY) {
        return js_promise_combinator_iterable_with_constructor(constructor, iterable, kind, promise, resolve, reject);
    }

    Item arr_item = ItemNull;
    Item rejection = ItemNull;
    if (!js_promise_materialize_iterable(iterable, &arr_item, &rejection)) {
        js_promise_call_capability_reject(reject, rejection);
        return promise;
    }

    Array* arr = arr_item.array;
    Item resolve_method = js_property_get(constructor, (Item){.item = s2it(heap_create_name("resolve", 7))});
    if (js_check_exception()) {
        Item error = js_clear_exception();
        js_promise_call_capability_reject(reject, error);
        return promise;
    }
    if (get_type_id(resolve_method) != LMD_TYPE_FUNC) {
        Item error = js_promise_make_type_error("Promise resolve is not callable", 31);
        js_promise_call_capability_reject(reject, error);
        return promise;
    }

    if (arr->length == 0) {
        if (kind == 0 || kind == 1) {
            js_promise_call_capability_resolve(resolve, reject, js_array_new(0));
        } else if (kind == 2) {
            js_promise_call_capability_reject(reject, js_promise_make_aggregate_error(js_array_new(0)));
        }
        return promise;
    }

    Item resolved_arr = ItemNull;
    if (!js_promise_resolve_elements_with_constructor(constructor, resolve_method,
        arr_item, &resolved_arr, reject)) {
        return promise;
    }

    if (kind == 3) {
        Array* resolved = resolved_arr.array;
        for (int i = 0; i < resolved->length; i++) {
            Item error = ItemNull;
            if (!js_invoke_promise_then(resolved->items[i], resolve, reject, &error)) {
                js_promise_call_capability_reject(reject, error);
                return promise;
            }
        }
        return promise;
    }

    Item native = ItemNull;
    if (kind == 0) native = js_promise_all(resolved_arr);
    else if (kind == 1) native = js_promise_all_settled(resolved_arr);
    else if (kind == 2) native = js_promise_any(resolved_arr);

    if (js_check_exception()) {
        Item error = js_clear_exception();
        js_promise_call_capability_reject(reject, error);
        return promise;
    }
    js_promise_forward_native_to_capability(native, resolve, reject);
    return promise;
}

static Item js_promise_all_with_constructor(Item constructor, Item iterable) {
    return js_promise_combinator_with_constructor(constructor, iterable, 0);
}

static Item js_promise_all_settled_with_constructor(Item constructor, Item iterable) {
    return js_promise_combinator_with_constructor(constructor, iterable, 1);
}

static Item js_promise_any_with_constructor(Item constructor, Item iterable) {
    return js_promise_combinator_with_constructor(constructor, iterable, 2);
}

static Item js_promise_race_with_constructor(Item constructor, Item iterable) {
    return js_promise_combinator_with_constructor(constructor, iterable, 3);
}

static Item js_promise_with_resolvers_for_constructor(Item constructor) {
    if (!js_promise_is_object_like(constructor)) {
        return js_throw_type_error("Promise.withResolvers requires an object constructor");
    }
    if (!js_is_constructor_internal(constructor)) {
        return js_throw_type_error("Promise.withResolvers requires a constructor");
    }
    Item resolve_fn = ItemNull;
    Item reject_fn = ItemNull;
    Item promise = js_promise_new_capability(constructor, &resolve_fn, &reject_fn);
    if (js_check_exception()) return ItemNull;

    // Build { promise, resolve, reject } object
    Item result = js_new_object();
    Item k_promise = (Item){.item = s2it(heap_create_name("promise"))};
    Item k_resolve = (Item){.item = s2it(heap_create_name("resolve"))};
    Item k_reject = (Item){.item = s2it(heap_create_name("reject"))};
    js_property_set(result, k_promise, promise);
    js_property_set(result, k_resolve, resolve_fn);
    js_property_set(result, k_reject, reject_fn);
    return result;
}

extern "C" Item js_promise_with_resolvers(void) {
    return js_promise_with_resolvers_for_constructor(js_promise_default_constructor());
}

// Phase 5: Synchronous await — unwraps resolved promises, throws on rejected
extern "C" Item js_await_sync(Item value) {
    extern void js_run_microtasks(void);
    // If not a promise, check for thenable per ES spec PromiseResolve.
    // For TLA without state machine, we can only synchronously resolve thenables
    // whose .then() invokes resolve() synchronously.
    JsPromise* p = js_get_promise(value);
    if (!p) {
        if (js_promise_is_object_like(value)) {
            Item wrapped = js_promise_resolve(value);
            p = js_get_promise(wrapped);
            if (p) {
                // js_promise_resolve_with_value enqueues thenable.then(resolve, reject)
                // as a microtask. Drain microtasks so the resolve callback fires
                // before we read p->state. This handles thenables whose .then()
                // invokes resolve() synchronously.
                if (p->state == JS_PROMISE_PENDING) {
                    js_run_microtasks();
                }
                if (p->state == JS_PROMISE_FULFILLED) {
                    return p->result;
                }
                if (p->state == JS_PROMISE_REJECTED) {
                    js_throw_value(p->result);
                    return ItemNull;
                }
                // Pending — sync fast-path can't suspend
                log_debug("js: await_sync: thenable pending (no async state machine yet)");
                return make_js_undefined();
            }
        }
        // Js56 P9: even for non-promise/non-thenable awaits, the ES spec
        // wraps the value in `PromiseResolve(X)` and yields to the microtask
        // queue. Without draining microtasks here, tests that rely on
        // observable tick ordering (e.g.
        // `Promise.resolve().then(...); await 1; assert(...)`) see stale
        // state. The drain is bounded by TASK_FLUSH_SAFETY_LIMIT.
        js_run_microtasks();
        return value;
    }

    if (p->state == JS_PROMISE_FULFILLED) {
        // Js56 P10: per ES spec, even a fulfilled promise await yields to the
        // microtask queue before resuming. Drain microtasks first so any
        // pending `.then()` handlers fire in the correct order relative to
        // continuation. Mirrors the non-promise drain above.
        js_run_microtasks();
        return p->result;
    }
    if (p->state == JS_PROMISE_REJECTED) {
        js_run_microtasks();
        // Rejected promise: throw the rejection reason
        js_throw_value(p->result);
        return ItemNull;
    }
    // Js56 H1: pending direct Promise — drain microtasks once, then re-check.
    // Handles `await Promise.resolve(1).then(...).then(...)` where the chained
    // then handlers run as microtasks and only resolve the awaited promise after
    // the queue is flushed. Drain is bounded by TASK_FLUSH_SAFETY_LIMIT (see
    // js_event_loop.cpp:js_microtask_flush).
    js_run_microtasks();
    if (p->state == JS_PROMISE_FULFILLED) {
        return p->result;
    }
    if (p->state == JS_PROMISE_REJECTED) {
        js_throw_value(p->result);
        return ItemNull;
    }
    // Js57 P2c: bounded libuv loop drain so cross-module Promise resolution
    // (e.g. another async module fulfilling a shared `Promise.withResolvers()`
    // promise via a queued task) can still settle this await. Guarded by three
    // bounds (watchdog 100 ms, 3 no-progress turns, 64 turn cap) so that a
    // promise that genuinely cannot settle in this turn returns undefined
    // quickly — Js55 P23(b) hit 1675 s on the suite by drainin unconditionally.
    //
    // Conditional trigger: if the promise has no then-handlers queued AND no
    // pending nextTick / microtask is present, no future progress is possible
    // from this thread; return undefined immediately.
    if (p->then_count > 0 || js_microtask_pending_count() > 0) {
        struct AwaitPredCtx { JsPromise* p; };
        AwaitPredCtx ctx = { p };
        auto predicate = [](void* u) -> int {
            JsPromise* pp = ((AwaitPredCtx*)u)->p;
            return pp->state != JS_PROMISE_PENDING ? 1 : 0;
        };
        js_await_bounded_drain(predicate, &ctx, /*watchdog_ms=*/100,
                               /*max_no_progress=*/3, /*max_turns=*/64);
        if (p->state == JS_PROMISE_FULFILLED) {
            return p->result;
        }
        if (p->state == JS_PROMISE_REJECTED) {
            js_throw_value(p->result);
            return ItemNull;
        }
    }
    log_debug("js: await_sync: promise still pending after bounded drain");
    return make_js_undefined();
}

// ============================================================
// Phase 6: Async/Await Full State Machine Runtime
// ============================================================

// Async context: tracks a running async function's state machine
struct JsAsyncContext {
    void* state_fn;      // pointer to async_sm_<name> state machine function
    Item* env;           // env array (captures + params + locals)
    int env_size;
    int state;           // current resume state
    int promise_idx;     // index into js_promises[] for the async function's result promise
    Item this_val;       // receiver captured when the async wrapper was called
};

#define JS_MAX_ASYNC_CONTEXTS 256
static JsAsyncContext js_async_contexts[JS_MAX_ASYNC_CONTEXTS];
static int js_async_context_count = 0;

// Cached resolved value from js_async_must_suspend (fast-path)
static Item js_async_resolved_value;

static void js_async_register_roots_once() {
    static bool registered = false;
    if (registered) return;
    registered = true;

    extern void heap_register_gc_root_range(uint64_t* base, int count);
    for (int i = 0; i < JS_MAX_ASYNC_CONTEXTS; i++) {
        heap_register_gc_root_range((uint64_t*)&js_async_contexts[i].this_val, 1);
    }
    heap_register_gc_root_range((uint64_t*)&js_async_resolved_value, 1);
}

// Check if an awaited value requires suspension (pending promise)
// Returns: 1 = pending (must suspend), 0 = resolved/rejected/non-promise
// For resolved/non-promise: caches result in js_async_resolved_value
// For rejected: calls js_throw_value (exception mechanism handles it)
extern "C" int64_t js_async_must_suspend(Item value) {
    JsPromise* p = js_get_promise(value);
    if (!p) {
        if (js_promise_is_object_like(value)) {
            Item wrapped = js_promise_resolve(value);
            p = js_get_promise(wrapped);
            if (p) {
                if (p->state == JS_PROMISE_FULFILLED) {
                    js_async_resolved_value = p->result;
                    return 0;
                }
                if (p->state == JS_PROMISE_REJECTED) {
                    js_throw_value(p->result);
                    js_async_resolved_value = ItemNull;
                    return 0;
                }
                js_async_resolved_value = wrapped;
                return 1;
            }
        }
        js_async_resolved_value = value;
        return 0;
    }
    if (p->state == JS_PROMISE_FULFILLED) {
        js_async_resolved_value = p->result;
        return 0;
    }
    if (p->state == JS_PROMISE_REJECTED) {
        js_throw_value(p->result);
        js_async_resolved_value = ItemNull;
        return 0;
    }
    // Pending — must suspend
    js_async_resolved_value = value;
    return 1;
}

// Get the cached resolved value after js_async_must_suspend returned 0
extern "C" Item js_async_get_resolved(void) {
    return js_async_resolved_value;
}

// Forward declarations for async callbacks
static Item js_async_resume_handler(Item ctx_idx_item, Item resolved_value);
static Item js_async_reject_handler(Item ctx_idx_item, Item reason);

// Core async state machine driver: calls the state machine and handles results
static void js_async_drive(int ctx_idx, Item input, int64_t state) {
    JsAsyncContext* ctx = &js_async_contexts[ctx_idx];
    typedef Item (*AsyncSmFn)(Item*, Item, int64_t);
    Item prev_this = js_current_this;
    js_current_this = ctx->this_val;
    Item result = ((AsyncSmFn)ctx->state_fn)(ctx->env, input, state);
    js_current_this = prev_this;

    // Parse result: [value, next_state]
    if (get_type_id(result) != LMD_TYPE_ARRAY) {
        js_promise_settle(&js_promises[ctx->promise_idx], JS_PROMISE_REJECTED, result);
        return;
    }
    Array* arr = result.array;
    if (arr->length < 2) {
        js_promise_settle(&js_promises[ctx->promise_idx], JS_PROMISE_REJECTED, ItemNull);
        return;
    }
    Item value = arr->items[0];
    int64_t next_state = it2i(arr->items[1]);

    if (next_state == -1) {
        // Done — resolve the async function promise with the shared Promise
        // Resolution Procedure so returned promises/thenables are adopted.
        if (js_check_exception()) {
            js_clear_exception();
        }
        js_promise_resolve_with_value(&js_promises[ctx->promise_idx], value);
    } else if (next_state == -2) {
        // Rejected — reject the async function's promise
        js_promise_settle(&js_promises[ctx->promise_idx], JS_PROMISE_REJECTED, value);
    } else {
        // Suspended on pending promise — register resume/reject callbacks
        ctx->state = next_state;

        // Create bound resume callback: js_async_resume_handler(ctx_idx, resolved_val)
        Item resume_fn = js_new_function((void*)js_async_resume_handler, 2);
        Item idx_item = (Item){.item = i2it(ctx_idx)};
        Item bound_resume = js_bind_function(resume_fn, ItemNull, &idx_item, 1);

        // Create bound reject callback: js_async_reject_handler(ctx_idx, reason)
        Item reject_fn = js_new_function((void*)js_async_reject_handler, 2);
        Item bound_reject = js_bind_function(reject_fn, ItemNull, &idx_item, 1);

        // Register on the pending promise
        js_promise_then(value, bound_resume, bound_reject);
    }
}

// Callback when an awaited promise resolves — resumes the async state machine
static Item js_async_resume_handler(Item ctx_idx_item, Item resolved_value) {
    int ctx_idx = (int)it2i(ctx_idx_item);
    if (ctx_idx < 0 || ctx_idx >= js_async_context_count) return ItemNull;
    JsAsyncContext* ctx = &js_async_contexts[ctx_idx];
    js_async_drive(ctx_idx, resolved_value, ctx->state);
    return ItemNull;
}

// Callback when an awaited promise rejects — re-enter state machine with exception set
static Item js_async_reject_handler(Item ctx_idx_item, Item reason) {
    int ctx_idx = (int)it2i(ctx_idx_item);
    if (ctx_idx < 0 || ctx_idx >= js_async_context_count) return ItemNull;
    JsAsyncContext* ctx = &js_async_contexts[ctx_idx];
    // Set exception so the state machine's try/catch can handle it
    js_throw_value(reason);
    // Re-enter the state machine — it will check the exception and jump to catch
    js_async_drive(ctx_idx, ItemNull, ctx->state);
    return ItemNull;
}

// Create an async context: allocates promise, returns context index
extern "C" Item js_async_context_create(void* fn_ptr, Item* env, int64_t env_size, Item this_val) {
    js_async_register_roots_once();
    if (js_async_context_count >= JS_MAX_ASYNC_CONTEXTS) {
        log_error("js: async context limit reached (%d)", JS_MAX_ASYNC_CONTEXTS);
        return (Item){.item = i2it(-1)};
    }
    int idx = js_async_context_count++;
    JsAsyncContext* ctx = &js_async_contexts[idx];
    ctx->state_fn = fn_ptr;
    ctx->env = env;
    ctx->env_size = (int)env_size;
    ctx->state = 0;
    ctx->this_val = this_val;

    // Create a pending promise for this async function's result
    JsPromise* p = js_alloc_promise();
    ctx->promise_idx = (int)(p - js_promises);
    // async functions allocate their result promise before the body runs.
    js_promise_to_item(p);

    return (Item){.item = i2it(idx)};
}

// Start execution of an async state machine (initial call at state 0)
extern "C" Item js_async_start(Item ctx_idx_item) {
    int ctx_idx = (int)it2i(ctx_idx_item);
    if (ctx_idx < 0 || ctx_idx >= js_async_context_count) return ItemNull;
    js_async_drive(ctx_idx, make_js_undefined(), 0);
    return ItemNull;
}

// Get the result promise for an async context
extern "C" Item js_async_get_promise(Item ctx_idx_item) {
    int ctx_idx = (int)it2i(ctx_idx_item);
    if (ctx_idx < 0 || ctx_idx >= js_async_context_count) return ItemNull;
    JsAsyncContext* ctx = &js_async_contexts[ctx_idx];
    return js_promise_to_item(&js_promises[ctx->promise_idx]);
}

extern "C" Item js_promise_then(Item promise, Item on_fulfilled, Item on_rejected) {
    JsPromise* p = js_get_promise(promise);
    if (!p) return ItemNull;
    bool has_rejection_handler = get_type_id(on_rejected) == LMD_TYPE_FUNC;
    if (has_rejection_handler) {
        js_promise_mark_rejection_handled(p);
    }
    Item reaction_domain = js_domain_get_current();

    Item return_promise = ItemNull;
    Item capability_resolve = ItemNull;
    Item capability_reject = ItemNull;
    bool use_capability = false;
    Item capability_constructor = js_promise_species_constructor(promise);
    if (js_check_exception()) return ItemNull;
    if (!js_promise_is_builtin_promise_constructor(capability_constructor)) {
        return_promise = js_promise_new_capability(capability_constructor, &capability_resolve, &capability_reject);
        if (js_check_exception()) return ItemNull;
        use_capability = true;
    }

    // Create a native promise for the reaction chain.
    JsPromise* next = js_alloc_promise();
    if (!next) return ItemNull;
    Item next_item = js_promise_to_item(next);
    if (use_capability) {
        js_promise_forward_native_to_capability(next_item, capability_resolve, capability_reject);
        if (js_check_exception()) return ItemNull;
    } else {
        return_promise = next_item;
    }

    if (p->state == JS_PROMISE_PENDING) {
        // Register callbacks with chained next promise
        if (p->then_count < 8) {
            p->on_fulfilled[p->then_count] = on_fulfilled;
            p->on_rejected[p->then_count] = on_rejected;
            p->next_promise[p->then_count] = next_item;
            p->reaction_domain[p->then_count] = reaction_domain;
            p->then_count++;
        }
    } else if (p->state == JS_PROMISE_FULFILLED) {
        if (get_type_id(on_fulfilled) == LMD_TYPE_FUNC) {
            // per spec: schedule as microtask even if already resolved
            js_promise_enqueue_handler_domain(on_fulfilled, p->result, next_item, reaction_domain);
        } else {
            js_promise_enqueue_passthrough(next_item, JS_PROMISE_FULFILLED, p->result, reaction_domain);
        }
    } else {
        if (get_type_id(on_rejected) == LMD_TYPE_FUNC) {
            js_promise_enqueue_handler_domain(on_rejected, p->result, next_item, reaction_domain);
        } else {
            js_promise_enqueue_passthrough(next_item, JS_PROMISE_REJECTED, p->result, reaction_domain);
        }
    }

    return return_promise;
}

extern "C" Item js_promise_catch(Item promise, Item on_rejected) {
    Item undef = (Item){.item = ((uint64_t)LMD_TYPE_UNDEFINED << 56)};
    return js_promise_then(promise, undef, on_rejected);
}

extern "C" Item js_promise_finally(Item promise, Item on_finally) {
    if (!js_promise_is_object_like(promise)) {
        return js_throw_type_error("Promise.prototype.finally called on non-object");
    }
    Item constructor = js_promise_species_constructor(promise);
    if (js_check_exception()) return ItemNull;

    Item then_finally = on_finally;
    Item catch_finally = on_finally;
    if (get_type_id(on_finally) == LMD_TYPE_FUNC) {
        then_finally = js_promise_make_finally_wrapper((void*)js_promise_then_finally,
            on_finally, constructor);
        catch_finally = js_promise_make_finally_wrapper((void*)js_promise_catch_finally,
            on_finally, constructor);
    }
    return js_promise_invoke_then(promise, then_finally, catch_finally);
}

